import React from 'react';
import type { Metadata } from "next";
import { DM_Sans, Instrument_Serif } from "next/font/google";
import { Providers } from "@/components/providers";
import "./globals.css";

const dmSans = DM_Sans({ subsets: ["latin"], variable: "--font-sans" });
const instrumentSerif = Instrument_Serif({
  weight: "400",
  subsets: ["latin"],
  style: "italic",
  variable: "--font-serif"
});

export const metadata: Metadata = {
  title: {
    default: "CitedBy.ai вҖ” Plateforme d'optimisation AEO",
    template: "%s | CitedBy.ai",
  },
  description: "Surveillez et optimisez la visibilite de votre marque dans les reponses des moteurs IA (ChatGPT, Perplexity, Gemini, Claude).",
  metadataBase: new URL(process.env.NEXT_PUBLIC_APP_URL || "https://citedby.ai"),
  openGraph: {
    type: "website",
    siteName: "CitedBy.ai",
    title: "CitedBy.ai вҖ” Plateforme d'optimisation AEO",
    description: "Surveillez et optimisez la visibilite de votre marque dans les reponses des moteurs IA.",
  },
  twitter: {
    card: "summary_large_image",
    title: "CitedBy.ai вҖ” Plateforme d'optimisation AEO",
    description: "Surveillez et optimisez la visibilite de votre marque dans les reponses des moteurs IA.",
  },
  robots: {
    index: true,
    follow: true,
  },
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="fr" className="dark">
      <body className={`${dmSans.variable} ${instrumentSerif.variable} font-sans antialiased bg-background text-foreground`}>
        <a href="#main-content" className="skip-to-content">
          Aller au contenu principal
        </a>
        <Providers>
          <div id="main-content">
            {children}
          </div>
        </Providers>
      </body>
    </html>
  );
}

