import React, { createContext, useContext, useState, useCallback, useMemo, useEffect } from 'react';
import { Locale, TranslationDictionary, SUPPORTED_LOCALES } from './types';
import fr from './locales/fr';
import en from './locales/en';
import es from './locales/es';

// ================================================================
// DICTIONNAIRES
// ================================================================

const dictionaries: Record<Locale, TranslationDictionary> = { fr, en, es };

// ================================================================
// CONTEXT
// ================================================================

interface I18nContextValue {
  locale: Locale;
  setLocale: (locale: Locale) => void;
  t: TranslationDictionary;
  /** Format a template string like "Hello {name}" with values */
  tf: (template: string, values: Record<string, string | number>) => string;
  /** Get the AI prompt language instruction for the current locale */
  promptLang: string;
}

const I18nContext = createContext<I18nContextValue | null>(null);

// ================================================================
// STORAGE KEY
// ================================================================

const LOCALE_STORAGE_KEY = 'citedby_locale';

const getInitialLocale = (): Locale => {
  // 1. Check localStorage
  if (typeof window !== 'undefined') {
    const stored = localStorage.getItem(LOCALE_STORAGE_KEY);
    if (stored && ['fr', 'en', 'es'].includes(stored)) {
      return stored as Locale;
    }
    // 2. Check browser language
    const browserLang = navigator.language.slice(0, 2);
    if (['fr', 'en', 'es'].includes(browserLang)) {
      return browserLang as Locale;
    }
  }
  // 3. Default to French
  return 'fr';
};

// ================================================================
// PROVIDER
// ================================================================

interface I18nProviderProps {
  children: React.ReactNode;
  defaultLocale?: Locale;
}

export const I18nProvider: React.FC<I18nProviderProps> = ({ children, defaultLocale }) => {
  const [locale, setLocaleState] = useState<Locale>(defaultLocale || getInitialLocale());

  const setLocale = useCallback((newLocale: Locale) => {
    setLocaleState(newLocale);
    if (typeof window !== 'undefined') {
      localStorage.setItem(LOCALE_STORAGE_KEY, newLocale);
    }
  }, []);

  // Persist on change
  useEffect(() => {
    if (typeof window !== 'undefined') {
      localStorage.setItem(LOCALE_STORAGE_KEY, locale);
    }
  }, [locale]);

  const t = useMemo(() => dictionaries[locale], [locale]);

  const tf = useCallback((template: string, values: Record<string, string | number>) => {
    let result = template;
    for (const [key, value] of Object.entries(values)) {
      result = result.replace(new RegExp(`\\{${key}\\}`, 'g'), String(value));
    }
    return result;
  }, []);

  const promptLang = useMemo(() => t.prompts.outputLanguageInstruction, [t]);

  const value = useMemo<I18nContextValue>(() => ({
    locale,
    setLocale,
    t,
    tf,
    promptLang,
  }), [locale, setLocale, t, tf, promptLang]);

  return (
    <I18nContext.Provider value={value}>
      {children}
    </I18nContext.Provider>
  );
};

// ================================================================
// HOOKS
// ================================================================

export const useTranslation = (): I18nContextValue => {
  const context = useContext(I18nContext);
  if (!context) {
    throw new Error('useTranslation must be used within an I18nProvider');
  }
  return context;
};

/** Shortcut hook to get just the locale and setter */
export const useLocale = (): { locale: Locale; setLocale: (l: Locale) => void } => {
  const { locale, setLocale } = useTranslation();
  return { locale, setLocale };
};

