import React, { useState } from 'react';
import { CategoryScore } from '../types';
import { ChevronDown, ChevronUp, CheckCircle, AlertTriangle, XCircle } from 'lucide-react';

interface CategoryCardProps {
  category: CategoryScore;
  simple?: boolean;
}

const CategoryCard: React.FC<CategoryCardProps> = ({ category, simple = false }) => {
  const [isExpanded, setIsExpanded] = useState(false);

  const getStatusIcon = (status: 'success' | 'warning' | 'error') => {
    switch (status) {
      case 'success': return <CheckCircle size={18} className="text-emerald-500" />;
      case 'warning': return <AlertTriangle size={18} className="text-amber-500" />;
      case 'error': return <XCircle size={18} className="text-red-500" />;
    }
  };

  const getScoreColor = (score: number) => {
    if (score >= 80) return 'text-emerald-400';
    if (score >= 60) return 'text-amber-400';
    return 'text-red-400';
  };

  return (
    <div className={`glass-panel rounded-xl overflow-hidden mb-4 transition-all duration-300 hover:bg-white/5 ${simple ? '' : 'cursor-pointer'}`}>
      <div 
        className="p-4 flex items-center justify-between"
        onClick={() => !simple && setIsExpanded(!isExpanded)}
      >
        <div className="flex items-center gap-4">
          <div className={`w-12 h-12 rounded-full flex items-center justify-center bg-white/5 font-bold ${getScoreColor(category.score)}`}>
            {category.score}
          </div>
          <div>
            <h3 className="font-semibold text-lg">{category.name}</h3>
            <p className="text-sm text-gray-400">{category.items.length} critГЁres analysГ©s</p>
          </div>
        </div>
        {!simple && (
          <button className="text-gray-400 hover:text-white">
            {isExpanded ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
          </button>
        )}
      </div>

      {!simple && isExpanded && (
        <div className="px-4 pb-4 border-t border-white/5 bg-black/20">
          <div className="mt-3 space-y-3">
            {category.items.map((item, idx) => (
              <div key={idx} className="flex items-start gap-3 text-sm p-2 rounded hover:bg-white/5">
                <span className="mt-0.5">{getStatusIcon(item.status)}</span>
                <span className="text-gray-300">{item.message}</span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default CategoryCard;

