import React from 'react';
import { Recommendation, GeneratedSolution } from '../types';
import { Zap, TrendingUp, Clock, CheckCircle2, Lock, Eye, Check } from 'lucide-react';

interface Props {
  rec: Recommendation;
  cost: number;
  onApply: (rec: Recommendation) => void;
  existingSolution?: GeneratedSolution | null;
  onView?: (solution: GeneratedSolution) => void;
}

const RecommendationCard: React.FC<Props> = ({ rec, cost, onApply, existingSolution, onView }) => {
  const getBadgeColor = (p: string) => {
    switch(p) {
      case 'critical': return 'bg-red-500/20 text-red-300 border-red-500/30';
      case 'high': return 'bg-orange-500/20 text-orange-300 border-orange-500/30';
      case 'medium': return 'bg-amber-500/20 text-amber-300 border-amber-500/30';
      default: return 'bg-blue-500/20 text-blue-300 border-blue-500/30';
    }
  };

  const handleButtonClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (existingSolution && onView) {
      onView(existingSolution);
    } else {
      onApply(rec);
    }
  };

  return (
    <div className={`glass-panel p-5 rounded-xl border transition-all border-white/10 hover:border-primary/30`}>
      <div className="flex justify-between items-start mb-3">
        <span className={`px-2 py-1 rounded text-xs font-semibold uppercase tracking-wider border ${getBadgeColor(rec.priority)}`}>
          {rec.priority}
        </span>
        <span className="text-xs text-gray-500">{rec.category}</span>
      </div>

      <h3 className="text-lg font-serif font-medium text-white mb-4">{rec.title}</h3>

      <div className={`p-3 rounded-lg mb-4 bg-white/5`}>
        <div className="flex items-start gap-2">
          {existingSolution ? (
             <Check className="text-emerald-400 shrink-0 mt-0.5" size={16} />
          ) : (
             <Zap className="text-accent shrink-0 mt-0.5" size={16} />
          )}
          <p className="text-sm text-gray-200">
            <span className={`font-semibold ${existingSolution ? 'text-emerald-400' : 'text-accent'}`}>
                {existingSolution ? 'Solution disponible :' : 'Action requise :'}
            </span> {rec.action}
          </p>
        </div>
      </div>

      <div className="flex items-center justify-between text-xs text-gray-500 border-t border-white/10 pt-3">
        <div className="flex gap-4">
          <span className="flex items-center gap-1">
            <Clock size={12} /> Effort: <span className="text-gray-300 capitalize">{rec.effort}</span>
          </span>
          <span className="flex items-center gap-1">
            <TrendingUp size={12} /> Impact: <span className="text-gray-300 capitalize">{rec.impact}</span>
          </span>
        </div>

        <button 
            onClick={handleButtonClick}
            className={`
                px-3 py-1.5 rounded-lg flex items-center gap-2 font-medium transition-all group active:scale-95 transform border
                ${existingSolution 
                    ? 'bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-400 border-emerald-500/20 hover:border-emerald-500/50' 
                    : 'bg-primary/10 hover:bg-primary/20 text-primary border-primary/20 hover:border-primary/50'}
            `}
        >
            {existingSolution ? <Eye size={12} className="fill-current" /> : <Zap size={12} className="fill-current" />}
            <span>{existingSolution ? 'Voir la solution' : `GГ©nГ©rer Solution (-${cost})`}</span>
        </button>
      </div>
    </div>
  );
};

export default RecommendationCard;

