"use client"

import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from "recharts"

interface DataPoint {
  date: string
  score: number
  citations: number
  mentions: number
}

interface VisibilityTrendChartProps {
  data: DataPoint[]
  metric?: "score" | "citations" | "mentions"
}

const METRIC_CONFIG = {
  score: { color: "#10b981", label: "Score AEO" },
  citations: { color: "#3b82f6", label: "Citations" },
  mentions: { color: "#f59e0b", label: "Mentions" },
}

export function VisibilityTrendChart({ data, metric = "score" }: VisibilityTrendChartProps) {
  const config = METRIC_CONFIG[metric]

  return (
    <ResponsiveContainer width="100%" height={300}>
      <AreaChart data={data} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
        <defs>
          <linearGradient id={`gradient-${metric}`} x1="0" y1="0" x2="0" y2="1">
            <stop offset="5%" stopColor={config.color} stopOpacity={0.3} />
            <stop offset="95%" stopColor={config.color} stopOpacity={0} />
          </linearGradient>
        </defs>
        <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.05)" />
        <XAxis
          dataKey="date"
          stroke="rgba(255,255,255,0.2)"
          tick={{ fill: "rgba(255,255,255,0.4)", fontSize: 12 }}
          axisLine={false}
          tickLine={false}
        />
        <YAxis
          stroke="rgba(255,255,255,0.2)"
          tick={{ fill: "rgba(255,255,255,0.4)", fontSize: 12 }}
          axisLine={false}
          tickLine={false}
          domain={metric === "score" ? [0, 100] : ["auto", "auto"]}
        />
        <Tooltip
          contentStyle={{
            backgroundColor: "#1a1d21",
            border: "1px solid rgba(255,255,255,0.1)",
            borderRadius: "12px",
            color: "#fff",
          }}
          labelStyle={{ color: "rgba(255,255,255,0.5)" }}
        />
        <Area
          type="monotone"
          dataKey={metric}
          stroke={config.color}
          strokeWidth={2}
          fill={`url(#gradient-${metric})`}
          dot={false}
          activeDot={{ r: 5, fill: config.color, stroke: "#0a0a0f", strokeWidth: 2 }}
        />
      </AreaChart>
    </ResponsiveContainer>
  )
}

