'use client';

import React from "react";
import Link from "next/link";
import { ArrowLeft } from "lucide-react";
import { usePathname } from "next/navigation";
import { cn } from "@/lib/utils";

export default function ProjectLayout({
  children,
  params
}: {
  children: React.ReactNode;
  params: { id: string };
}) {
  const pathname = usePathname();
  const baseUrl = `/app/projects/${params.id}`;

  const tabs = [
    { label: "Vue d'ensemble", href: `${baseUrl}/overview` },
    { label: "VisibilitГ© IA", href: `${baseUrl}/ai-visibility` },
    { label: "Citations", href: `${baseUrl}/citations` },
    { label: "Recommandations", href: `${baseUrl}/recommendations` },
    { label: "Packs Contenu", href: `${baseUrl}/packs` },
  ];

  return (
    <div className="p-8 max-w-7xl mx-auto">
      <div className="mb-6">
        <Link href="/app/projects" className="text-sm text-gray-400 hover:text-white flex items-center gap-2 mb-4">
          <ArrowLeft size={16} /> Retour aux projets
        </Link>
        <div className="flex items-center gap-4 overflow-x-auto pb-2 border-b border-white/10 no-scrollbar">
           {tabs.map((tab) => {
             const isActive = pathname === tab.href;
             return (
               <Link 
                 key={tab.href}
                 href={tab.href} 
                 className={cn(
                   "px-4 py-2 text-sm font-medium transition-colors whitespace-nowrap",
                   isActive 
                    ? "text-white border-b-2 border-primary" 
                    : "text-gray-400 hover:text-white border-b-2 border-transparent"
                 )}
               >
                 {tab.label}
               </Link>
             );
           })}
        </div>
      </div>
      {children}
    </div>
  );
}

"use client";

import { useState } from "react";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs";
import {
  BarChart3,
  TrendingUp,
  Eye,
  Quote,
  Target,
  ArrowUpRight,
  ArrowDownRight,
} from "lucide-react";

// Mock KPI data вҖ” will come from aggregated Supabase queries
const KPIS = {
  visibility: { value: 58, change: 12, label: "Score Visibilite IA" },
  citations: { value: 24, change: 8, label: "Citations detectees" },
  mentions: { value: 67, change: -3, label: "Mentions marque" },
  shareOfVoice: { value: 34, change: 5, label: "Part de voix" },
};

const TRENDS = [
  { date: "Sem 1", score: 42 },
  { date: "Sem 2", score: 45 },
  { date: "Sem 3", score: 51 },
  { date: "Sem 4", score: 58 },
];

const TOP_PROMPTS = [
  { prompt: "Meilleur outil AEO", citations: 8, sentiment: "positive" },
  { prompt: "Answer engine optimization", citations: 5, sentiment: "positive" },
  { prompt: "Etre cite par ChatGPT", citations: 4, sentiment: "neutral" },
  { prompt: "Optimisation IA entreprise", citations: 3, sentiment: "positive" },
  { prompt: "Schema.org generator", citations: 2, sentiment: "positive" },
];

export default function AnalyticsPage() {
  const [period, setPeriod] = useState("30d");

  return (
    <div className="p-8 max-w-7xl mx-auto">
      <header className="flex justify-between items-start mb-8">
        <div>
          <h1 className="text-3xl font-serif font-bold text-white mb-2">Analytics</h1>
          <p className="text-white/50">Vue d'ensemble de votre performance AEO.</p>
        </div>
        <div className="flex gap-1 bg-white/5 rounded-xl p-1">
          {["7d", "30d", "90d"].map((p) => (
            <button
              key={p}
              onClick={() => setPeriod(p)}
              className={`px-3 py-1.5 text-xs font-medium rounded-lg transition-colors ${
                period === p
                  ? "bg-primary text-black"
                  : "text-white/40 hover:text-white/70"
              }`}
            >
              {p === "7d" ? "7 jours" : p === "30d" ? "30 jours" : "90 jours"}
            </button>
          ))}
        </div>
      </header>

      {/* KPI Cards */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
        {Object.entries(KPIS).map(([key, kpi]) => (
          <Card key={key} className="p-5">
            <p className="text-xs text-white/40 uppercase mb-2">{kpi.label}</p>
            <div className="flex items-end justify-between">
              <p className="text-3xl font-bold text-white">{kpi.value}</p>
              <span className={`text-xs font-medium flex items-center gap-0.5 ${
                kpi.change >= 0 ? "text-emerald-400" : "text-red-400"
              }`}>
                {kpi.change >= 0 ? <ArrowUpRight size={12} /> : <ArrowDownRight size={12} />}
                {kpi.change >= 0 ? "+" : ""}{kpi.change}%
              </span>
            </div>
          </Card>
        ))}
      </div>

      <div className="grid lg:grid-cols-3 gap-6">
        {/* Trend Chart Placeholder */}
        <Card className="lg:col-span-2">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <TrendingUp size={18} className="text-primary" />
              Evolution de la visibilite
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="h-64 flex items-end gap-4 px-4">
              {TRENDS.map((t, i) => (
                <div key={i} className="flex-1 flex flex-col items-center gap-2">
                  <div
                    className="w-full bg-primary/20 rounded-t-lg transition-all hover:bg-primary/30 relative group"
                    style={{ height: `${(t.score / 100) * 200}px` }}
                  >
                    <div className="absolute -top-6 left-1/2 -translate-x-1/2 opacity-0 group-hover:opacity-100 text-xs font-bold text-primary transition-opacity">
                      {t.score}
                    </div>
                  </div>
                  <span className="text-xs text-white/30">{t.date}</span>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>

        {/* Top Prompts */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Target size={18} className="text-primary" />
              Top Prompts
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              {TOP_PROMPTS.map((p, i) => (
                <div key={i} className="flex items-center justify-between py-2">
                  <div className="flex-1 min-w-0">
                    <p className="text-sm text-white truncate">{p.prompt}</p>
                    <p className="text-xs text-white/30">{p.citations} citations</p>
                  </div>
                  <Badge
                    variant={p.sentiment === "positive" ? "success" : "secondary"}
                    className="ml-2 shrink-0"
                  >
                    {p.sentiment === "positive" ? "+" : "="}
                  </Badge>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Select } from "@/components/ui/select";
import { useWorkspace } from "@/lib/workspace-context";
import { toast } from "sonner";
import { Save, Building2, Globe, Shield } from "lucide-react";

export default function SettingsPage() {
  const { workspace } = useWorkspace();
  const [saving, setSaving] = useState(false);

  const handleSave = async () => {
    setSaving(true);
    // TODO: Save to Supabase
    await new Promise((r) => setTimeout(r, 500));
    toast.success("Parametres enregistres");
    setSaving(false);
  };

  return (
    <div className="p-8 max-w-4xl mx-auto">
      <header className="mb-8">
        <h1 className="text-3xl font-serif font-bold text-white mb-2">Parametres</h1>
        <p className="text-white/50">Gerez les parametres de votre espace de travail.</p>
      </header>

      <div className="space-y-6">
        {/* Organization */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Building2 size={18} className="text-primary" />
              Organisation
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <Input
              label="Nom de l'organisation"
              defaultValue={workspace?.name || ""}
              placeholder="Mon Entreprise"
            />
            <Select
              label="Secteur d'activite"
              options={[
                { value: "saas", label: "SaaS / Tech" },
                { value: "ecommerce", label: "E-commerce" },
                { value: "finance", label: "Finance" },
                { value: "sante", label: "Sante" },
                { value: "immobilier", label: "Immobilier" },
                { value: "education", label: "Education" },
                { value: "other", label: "Autre" },
              ]}
              placeholder="Choisir un secteur"
            />
          </CardContent>
        </Card>

        {/* Preferences */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Globe size={18} className="text-primary" />
              Preferences
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <Select
              label="Langue par defaut"
              options={[
                { value: "fr", label: "Francais" },
                { value: "en", label: "English" },
                { value: "es", label: "Espanol" },
              ]}
              defaultValue="fr"
            />
            <Select
              label="Fuseau horaire"
              options={[
                { value: "Europe/Paris", label: "Europe/Paris (UTC+1)" },
                { value: "America/New_York", label: "America/New_York (UTC-5)" },
                { value: "America/Los_Angeles", label: "America/Los_Angeles (UTC-8)" },
              ]}
              defaultValue="Europe/Paris"
            />
          </CardContent>
        </Card>

        {/* Security */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Shield size={18} className="text-primary" />
              Securite
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <Input
              label="Email du compte"
              type="email"
              disabled
              defaultValue="user@example.com"
            />
            <Button variant="outline" size="sm">
              Changer le mot de passe
            </Button>
          </CardContent>
        </Card>

        <div className="flex justify-end">
          <Button onClick={handleSave} isLoading={saving}>
            <Save size={16} /> Enregistrer
          </Button>
        </div>
      </div>
    </div>
  );
}

