"use client";

import { useState, useEffect } from "react";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Modal, ModalHeader, ModalBody, ModalFooter } from "@/components/ui/modal";
import {
  Key,
  Plus,
  Copy,
  Check,
  Trash2,
  Shield,
  Clock,
  AlertTriangle,
  Code,
} from "lucide-react";
import { toast } from "sonner";

interface ApiKey {
  id: string;
  name: string;
  key_prefix: string;
  scopes: string[];
  rate_limit: number;
  last_used_at: string | null;
  is_active: boolean;
  created_at: string;
}

export default function ApiSettingsPage() {
  const [keys, setKeys] = useState<ApiKey[]>([]);
  const [loading, setLoading] = useState(true);
  const [showCreate, setShowCreate] = useState(false);
  const [creating, setCreating] = useState(false);
  const [newKeyName, setNewKeyName] = useState("");
  const [revealedKey, setRevealedKey] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    loadKeys();
  }, []);

  const loadKeys = async () => {
    try {
      const res = await fetch("/api/keys");
      const data = await res.json();
      setKeys(data.keys || []);
    } catch {
      // No keys yet
    } finally {
      setLoading(false);
    }
  };

  const handleCreate = async () => {
    if (!newKeyName.trim()) {
      toast.error("Donnez un nom a la cle");
      return;
    }

    setCreating(true);
    try {
      const res = await fetch("/api/keys", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: newKeyName, scopes: ["read", "write"] }),
      });

      const data = await res.json();

      if (data.key) {
        setRevealedKey(data.key);
        setKeys((prev) => [{ ...data.details, is_active: true }, ...prev]);
        setNewKeyName("");
        toast.success("Cle API creee");
      } else {
        toast.error(data.error || "Erreur");
      }
    } catch {
      toast.error("Erreur de connexion");
    } finally {
      setCreating(false);
    }
  };

  const handleDelete = async (keyId: string) => {
    try {
      const res = await fetch("/api/keys", {
        method: "DELETE",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ keyId }),
      });

      const data = await res.json();
      if (data.success) {
        setKeys((prev) =>
          prev.map((k) => (k.id === keyId ? { ...k, is_active: false } : k))
        );
        toast.success("Cle desactivee");
      }
    } catch {
      toast.error("Erreur");
    }
  };

  const handleCopyKey = (key: string) => {
    navigator.clipboard.writeText(key);
    setCopied(true);
    toast.success("Cle copiee dans le presse-papier");
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div>
      <div className="flex justify-between items-center mb-8">
        <div>
          <h2 className="text-2xl font-serif font-bold text-white mb-2">API</h2>
          <p className="text-white/40">
            Gerez vos cles API pour acceder a l&apos;API REST CitedBy.ai
          </p>
        </div>
        <Button onClick={() => setShowCreate(true)}>
          <Plus size={16} /> Nouvelle cle
        </Button>
      </div>

      {/* API Documentation Card */}
      <Card className="mb-8">
        <CardHeader>
          <CardTitle className="text-base flex items-center gap-2">
            <Code size={16} className="text-primary" />
            Documentation API
          </CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-sm text-white/50 mb-4">
            Utilisez l&apos;API REST pour integrer CitedBy.ai dans vos outils.
          </p>

          <div className="space-y-3">
            <div className="rounded-xl bg-white/[0.02] border border-white/5 p-4">
              <div className="flex items-center gap-2 mb-2">
                <Badge variant="success">GET</Badge>
                <code className="text-sm text-white/70">/api/v1/projects</code>
              </div>
              <p className="text-xs text-white/40">Liste tous vos projets</p>
            </div>

            <div className="rounded-xl bg-white/[0.02] border border-white/5 p-4">
              <div className="flex items-center gap-2 mb-2">
                <Badge variant="success">GET</Badge>
                <code className="text-sm text-white/70">/api/v1/scores?projectId=xxx</code>
              </div>
              <p className="text-xs text-white/40">
                Scores de visibilite IA et details par moteur
              </p>
            </div>

            <div className="rounded-xl bg-white/[0.02] border border-white/5 p-4">
              <div className="flex items-center gap-2 mb-2">
                <Badge variant="success">GET</Badge>
                <code className="text-sm text-white/70">/api/v1/runs?projectId=xxx</code>
              </div>
              <p className="text-xs text-white/40">
                Historique des analyses (scans)
              </p>
            </div>
          </div>

          <div className="mt-4 p-3 rounded-lg bg-white/[0.02] border border-white/5">
            <p className="text-xs text-white/40 mb-2">Authentification :</p>
            <code className="text-xs text-primary">
              Authorization: Bearer cb_votre_cle_api
            </code>
          </div>
        </CardContent>
      </Card>

      {/* API Keys List */}
      <Card>
        <CardHeader>
          <CardTitle className="text-base flex items-center gap-2">
            <Key size={16} className="text-primary" />
            Cles API ({keys.filter((k) => k.is_active).length} active{keys.filter((k) => k.is_active).length > 1 ? "s" : ""})
          </CardTitle>
        </CardHeader>
        <CardContent>
          {loading ? (
            <div className="flex justify-center py-8">
              <div className="w-6 h-6 border-2 border-primary border-t-transparent rounded-full animate-spin" />
            </div>
          ) : keys.length === 0 ? (
            <div className="text-center py-8">
              <Shield size={32} className="text-white/20 mx-auto mb-3" />
              <p className="text-sm text-white/50 mb-1">Aucune cle API</p>
              <p className="text-xs text-white/30">
                Creez une cle pour commencer a utiliser l&apos;API
              </p>
            </div>
          ) : (
            <div className="space-y-2">
              {keys.map((apiKey) => (
                <div
                  key={apiKey.id}
                  className="flex items-center justify-between p-4 rounded-xl bg-white/[0.02] border border-white/5"
                >
                  <div className="flex items-center gap-3">
                    <Key size={16} className={apiKey.is_active ? "text-primary" : "text-white/20"} />
                    <div>
                      <p className={`text-sm font-medium ${apiKey.is_active ? "text-white" : "text-white/30 line-through"}`}>
                        {apiKey.name}
                      </p>
                      <div className="flex items-center gap-3 mt-0.5">
                        <code className="text-xs text-white/40">{apiKey.key_prefix}</code>
                        {apiKey.last_used_at && (
                          <span className="text-[10px] text-white/20 flex items-center gap-0.5">
                            <Clock size={8} /> Utilise {new Date(apiKey.last_used_at).toLocaleDateString("fr-FR")}
                          </span>
                        )}
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <Badge variant={apiKey.is_active ? "success" : "secondary"}>
                      {apiKey.is_active ? "Active" : "Desactivee"}
                    </Badge>
                    {apiKey.is_active && (
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => handleDelete(apiKey.id)}
                      >
                        <Trash2 size={14} className="text-red-400" />
                      </Button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Create Key Modal */}
      <Modal isOpen={showCreate && !revealedKey} onClose={() => setShowCreate(false)}>
        <ModalHeader onClose={() => setShowCreate(false)}>
          <h3 className="text-lg font-semibold text-white">Creer une cle API</h3>
        </ModalHeader>
        <ModalBody>
          <Input
            label="Nom de la cle"
            placeholder="Ex: Integration Zapier, Script monitoring..."
            value={newKeyName}
            onChange={(e) => setNewKeyName(e.target.value)}
          />
          <div className="mt-4 p-3 rounded-lg bg-amber-500/5 border border-amber-500/10">
            <p className="text-xs text-amber-400 flex items-center gap-1.5">
              <AlertTriangle size={12} />
              La cle ne sera affichee qu&apos;une seule fois apres creation.
            </p>
          </div>
        </ModalBody>
        <ModalFooter>
          <Button variant="ghost" onClick={() => setShowCreate(false)}>
            Annuler
          </Button>
          <Button onClick={handleCreate} isLoading={creating}>
            <Key size={14} /> Creer
          </Button>
        </ModalFooter>
      </Modal>

      {/* Revealed Key Modal */}
      <Modal isOpen={!!revealedKey} onClose={() => { setRevealedKey(null); setShowCreate(false); }}>
        <ModalHeader onClose={() => { setRevealedKey(null); setShowCreate(false); }}>
          <h3 className="text-lg font-semibold text-white">Votre nouvelle cle API</h3>
        </ModalHeader>
        <ModalBody>
          <div className="p-3 rounded-lg bg-white/5 border border-white/10">
            <code className="text-sm text-primary break-all">{revealedKey}</code>
          </div>
          <div className="mt-3 p-3 rounded-lg bg-red-500/5 border border-red-500/10">
            <p className="text-xs text-red-400 flex items-center gap-1.5">
              <AlertTriangle size={12} />
              Copiez cette cle maintenant. Elle ne sera plus affichee.
            </p>
          </div>
        </ModalBody>
        <ModalFooter>
          <Button onClick={() => handleCopyKey(revealedKey!)}>
            {copied ? <Check size={14} /> : <Copy size={14} />}
            {copied ? "Copiee !" : "Copier la cle"}
          </Button>
          <Button variant="ghost" onClick={() => { setRevealedKey(null); setShowCreate(false); }}>
            Fermer
          </Button>
        </ModalFooter>
      </Modal>
    </div>
  );
}

"use client";

import { useState } from "react";
import { Play, TrendingUp, Quote, Activity, Lightbulb, ArrowUpRight } from "lucide-react";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { VisibilityTrendChart } from "@/components/charts/visibility-trend-chart";
import { EngineBreakdownChart } from "@/components/charts/engine-breakdown-chart";
import { CompetitorChart } from "@/components/charts/competitor-chart";
import { toast } from "sonner";

// Mock data вҖ” will come from Supabase
const MOCK_TREND_DATA = [
  { date: "Sem 1", score: 42, citations: 2, mentions: 5 },
  { date: "Sem 2", score: 48, citations: 3, mentions: 8 },
  { date: "Sem 3", score: 55, citations: 5, mentions: 12 },
  { date: "Sem 4", score: 65, citations: 7, mentions: 15 },
];

const MOCK_ENGINE_DATA = [
  { engine: "ChatGPT", score: 72, mentions: 15, citations: 5 },
  { engine: "Perplexity", score: 58, mentions: 8, citations: 3 },
  { engine: "Gemini", score: 45, mentions: 5, citations: 1 },
  { engine: "Claude", score: 61, mentions: 10, citations: 4 },
  { engine: "Copilot", score: 33, mentions: 2, citations: 0 },
];

const MOCK_COMPETITOR_DATA = [
  { name: "Mon Site", mentions: 15 },
  { name: "Concurrent A", mentions: 22 },
  { name: "Concurrent B", mentions: 8 },
  { name: "Concurrent C", mentions: 5 },
];

interface RunSummary {
  globalScore: number
  totalPrompts: number
  citationsFound: number
  mentionsFound: number
  engineScores: Record<string, { score: number; mentions: number; citations: number }>
  alerts: Array<{ severity: string; message: string; action: string }>
}

export default function ProjectOverviewPage({ params }: { params: { id: string } }) {
  const [isRunning, setIsRunning] = useState(false);
  const [lastRun, setLastRun] = useState<RunSummary | null>(null);

  const handleRunAnalysis = async () => {
    setIsRunning(true);
    toast.loading("Analyse en cours...", { id: "run" });

    try {
      const res = await fetch("/api/runs/start", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ projectId: params.id }),
      });

      const data = await res.json();

      if (data.success) {
        setLastRun(data.summary);
        toast.success(
          `Analyse terminee ! Score: ${data.summary.globalScore}/100 вҖ” ${data.summary.citationsFound} citations, ${data.summary.mentionsFound} mentions`,
          { id: "run", duration: 5000 }
        );
      } else {
        toast.error(data.error || "Erreur lors de l'analyse", { id: "run" });
      }
    } catch {
      toast.error("Erreur de connexion", { id: "run" });
    } finally {
      setIsRunning(false);
    }
  };

  const displayScore = lastRun?.globalScore ?? 65;
  const displayCitations = lastRun?.citationsFound ?? 5;
  const displayMentions = lastRun?.mentionsFound ?? 12;

  return (
    <div>
      <div className="flex justify-between items-center mb-8">
        <h2 className="text-2xl font-serif font-bold text-white">Vue d'ensemble</h2>
        <Button onClick={handleRunAnalysis} isLoading={isRunning}>
          <Play size={16} /> {isRunning ? "Analyse en cours..." : "Lancer un Scan"}
        </Button>
      </div>

      {/* KPIs */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
        <Card className="p-5">
          <p className="text-xs text-white/40 uppercase mb-1">Score AEO</p>
          <p className="text-3xl font-bold text-white">{displayScore}<span className="text-sm text-white/30">/100</span></p>
          <span className="text-xs text-emerald-400 flex items-center gap-0.5 mt-1">
            <ArrowUpRight size={10} /> +12%
          </span>
        </Card>
        <Card className="p-5">
          <p className="text-xs text-white/40 uppercase mb-1">Mentions Marque</p>
          <p className="text-3xl font-bold text-white">{displayMentions}</p>
        </Card>
        <Card className="p-5">
          <p className="text-xs text-white/40 uppercase mb-1">Citations URL</p>
          <p className="text-3xl font-bold text-emerald-400">{displayCitations}</p>
        </Card>
        <Card className="p-5">
          <p className="text-xs text-white/40 uppercase mb-1">Recommandations</p>
          <p className="text-3xl font-bold text-amber-400">8</p>
        </Card>
      </div>

      {/* Charts */}
      <div className="grid lg:grid-cols-2 gap-6 mb-8">
        <Card>
          <CardHeader>
            <CardTitle className="text-base flex items-center gap-2">
              <TrendingUp size={16} className="text-primary" />
              Evolution sur 30 jours
            </CardTitle>
          </CardHeader>
          <CardContent>
            <VisibilityTrendChart data={MOCK_TREND_DATA} metric="score" />
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="text-base flex items-center gap-2">
              <Activity size={16} className="text-primary" />
              Score par moteur IA
            </CardTitle>
          </CardHeader>
          <CardContent>
            <EngineBreakdownChart data={MOCK_ENGINE_DATA} />
          </CardContent>
        </Card>
      </div>

      {/* Competitor Benchmark */}
      <Card className="mb-8">
        <CardHeader>
          <CardTitle className="text-base flex items-center gap-2">
            <Quote size={16} className="text-primary" />
            Part de voix vs concurrents
          </CardTitle>
        </CardHeader>
        <CardContent>
          <CompetitorChart data={MOCK_COMPETITOR_DATA} brandName="Mon Site" />
        </CardContent>
      </Card>

      {/* Alerts from last run */}
      {lastRun?.alerts && lastRun.alerts.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle className="text-base flex items-center gap-2">
              <Lightbulb size={16} className="text-primary" />
              Alertes du dernier scan
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-2">
              {lastRun.alerts.map((alert, i) => (
                <div key={i} className="flex items-start gap-3 p-3 rounded-xl bg-white/[0.02] border border-white/5">
                  <Badge
                    variant={
                      alert.severity === "critical" ? "destructive" :
                      alert.severity === "warning" ? "warning" : "default"
                    }
                  >
                    {alert.severity}
                  </Badge>
                  <div>
                    <p className="text-sm text-white">{alert.message}</p>
                    <p className="text-xs text-white/40 mt-0.5">{alert.action}</p>
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

"use client";

import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { EmptyState } from "@/components/ui/empty-state";
import { Button } from "@/components/ui/button";
import { Link2, ExternalLink, Quote, TrendingUp, Search } from "lucide-react";

interface Citation {
  id: string;
  aiEngine: string;
  prompt: string;
  excerpt: string;
  type: "direct" | "indirect" | "comparison";
  sentiment: "positive" | "neutral" | "negative";
  url_cited: boolean;
  date: string;
}

// Mock data вҖ” will come from Supabase run_results
const MOCK_CITATIONS: Citation[] = [
  {
    id: "1",
    aiEngine: "ChatGPT",
    prompt: "Quels sont les meilleurs outils d'optimisation AEO ?",
    excerpt: "CitedBy.ai est une plateforme qui aide les entreprises a optimiser leur presence dans les reponses des IA...",
    type: "direct",
    sentiment: "positive",
    url_cited: true,
    date: "2024-05-20",
  },
  {
    id: "2",
    aiEngine: "Perplexity",
    prompt: "Comment etre cite par les intelligences artificielles ?",
    excerpt: "Plusieurs outils existent pour ameliorer votre visibilite aupres des IA, notamment des solutions comme...",
    type: "indirect",
    sentiment: "neutral",
    url_cited: false,
    date: "2024-05-19",
  },
  {
    id: "3",
    aiEngine: "Gemini",
    prompt: "AEO optimization tools comparison",
    excerpt: "When comparing AEO tools, CitedBy.ai offers unique features like Schema.org generation and robots.txt optimization...",
    type: "comparison",
    sentiment: "positive",
    url_cited: true,
    date: "2024-05-18",
  },
];

const TYPE_BADGES: Record<string, { label: string; variant: "default" | "success" | "warning" | "secondary" }> = {
  direct: { label: "Citation directe", variant: "success" },
  indirect: { label: "Mention indirecte", variant: "default" },
  comparison: { label: "Comparaison", variant: "warning" },
};

const SENTIMENT_BADGES: Record<string, { label: string; variant: "success" | "secondary" | "destructive" }> = {
  positive: { label: "Positif", variant: "success" },
  neutral: { label: "Neutre", variant: "secondary" },
  negative: { label: "Negatif", variant: "destructive" },
};

export default function CitationsPage() {
  const urlCitations = MOCK_CITATIONS.filter((c) => c.url_cited).length;

  return (
    <div>
      <div className="flex justify-between items-center mb-8">
        <h2 className="text-2xl font-serif font-bold text-white">Citations</h2>
        <Button variant="outline">
          <Search size={16} /> Rechercher
        </Button>
      </div>

      {/* Summary */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
        <Card className="p-5">
          <p className="text-xs text-white/40 uppercase mb-1">Total citations</p>
          <p className="text-3xl font-bold text-white">{MOCK_CITATIONS.length}</p>
        </Card>
        <Card className="p-5">
          <p className="text-xs text-white/40 uppercase mb-1">Citations URL</p>
          <p className="text-3xl font-bold text-emerald-400">{urlCitations}</p>
        </Card>
        <Card className="p-5">
          <p className="text-xs text-white/40 uppercase mb-1">Mentions marque</p>
          <p className="text-3xl font-bold text-blue-400">{MOCK_CITATIONS.length - urlCitations}</p>
        </Card>
        <Card className="p-5">
          <p className="text-xs text-white/40 uppercase mb-1">Sentiment</p>
          <p className="text-lg font-bold text-emerald-400 flex items-center gap-1">
            <TrendingUp size={16} /> Positif
          </p>
        </Card>
      </div>

      {/* Citations List */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Quote size={18} className="text-primary" />
            Dernieres citations detectees
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="space-y-4">
            {MOCK_CITATIONS.map((citation) => {
              const typeInfo = TYPE_BADGES[citation.type];
              const sentimentInfo = SENTIMENT_BADGES[citation.sentiment];

              return (
                <div key={citation.id} className="p-4 rounded-xl border border-white/5 hover:border-white/10 transition-colors">
                  <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center gap-2">
                      <span className="text-sm font-medium text-white">{citation.aiEngine}</span>
                      <Badge variant={typeInfo.variant}>{typeInfo.label}</Badge>
                      <Badge variant={sentimentInfo.variant}>{sentimentInfo.label}</Badge>
                      {citation.url_cited && (
                        <Badge variant="success" className="gap-1">
                          <Link2 size={10} /> URL
                        </Badge>
                      )}
                    </div>
                    <span className="text-xs text-white/30">{citation.date}</span>
                  </div>

                  <p className="text-xs text-white/40 mb-2 flex items-center gap-1">
                    <Search size={12} /> Prompt: "{citation.prompt}"
                  </p>

                  <p className="text-sm text-white/70 leading-relaxed bg-white/[0.02] rounded-lg p-3 border-l-2 border-primary/30">
                    {citation.excerpt}
                  </p>
                </div>
              );
            })}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

