"use client";

import { useState } from "react";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs";
import { EmptyState } from "@/components/ui/empty-state";
import { Button } from "@/components/ui/button";
import { Eye, TrendingUp, TrendingDown, Minus, Play, Bot } from "lucide-react";

interface EngineVisibility {
  engine: string;
  score: number;
  trend: number;
  mentions: number;
  lastChecked: string;
}

// Mock data вҖ” will come from Supabase run_results
const MOCK_VISIBILITY: EngineVisibility[] = [
  { engine: "ChatGPT", score: 72, trend: 8, mentions: 15, lastChecked: "Il y a 2h" },
  { engine: "Perplexity", score: 58, trend: -3, mentions: 8, lastChecked: "Il y a 2h" },
  { engine: "Gemini", score: 45, trend: 12, mentions: 5, lastChecked: "Il y a 2h" },
  { engine: "Claude", score: 61, trend: 5, mentions: 10, lastChecked: "Il y a 2h" },
  { engine: "Copilot", score: 33, trend: 0, mentions: 2, lastChecked: "Il y a 2h" },
];

function ScoreColor({ score }: { score: number }) {
  if (score >= 70) return <span className="text-emerald-400">{score}</span>;
  if (score >= 50) return <span className="text-amber-400">{score}</span>;
  return <span className="text-red-400">{score}</span>;
}

function TrendIndicator({ value }: { value: number }) {
  if (value > 0) return <span className="text-emerald-400 text-xs flex items-center gap-0.5"><TrendingUp size={12} /> +{value}%</span>;
  if (value < 0) return <span className="text-red-400 text-xs flex items-center gap-0.5"><TrendingDown size={12} /> {value}%</span>;
  return <span className="text-white/30 text-xs flex items-center gap-0.5"><Minus size={12} /> 0%</span>;
}

export default function AIVisibilityPage() {
  const [tab, setTab] = useState("overview");

  const avgScore = Math.round(MOCK_VISIBILITY.reduce((s, v) => s + v.score, 0) / MOCK_VISIBILITY.length);

  return (
    <div>
      <div className="flex justify-between items-center mb-8">
        <h2 className="text-2xl font-serif font-bold text-white">Visibilite IA</h2>
        <Button>
          <Play size={16} /> Lancer un scan
        </Button>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
        <Card className="p-5">
          <p className="text-xs text-white/40 uppercase mb-1">Score global</p>
          <p className="text-3xl font-bold"><ScoreColor score={avgScore} /><span className="text-sm text-white/30">/100</span></p>
        </Card>
        <Card className="p-5">
          <p className="text-xs text-white/40 uppercase mb-1">Moteurs IA</p>
          <p className="text-3xl font-bold text-white">{MOCK_VISIBILITY.length}</p>
        </Card>
        <Card className="p-5">
          <p className="text-xs text-white/40 uppercase mb-1">Mentions totales</p>
          <p className="text-3xl font-bold text-white">{MOCK_VISIBILITY.reduce((s, v) => s + v.mentions, 0)}</p>
        </Card>
        <Card className="p-5">
          <p className="text-xs text-white/40 uppercase mb-1">Tendance</p>
          <div className="mt-1"><TrendIndicator value={Math.round(MOCK_VISIBILITY.reduce((s, v) => s + v.trend, 0) / MOCK_VISIBILITY.length)} /></div>
        </Card>
      </div>

      {/* Engine Breakdown */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Bot size={18} className="text-primary" />
            Visibilite par moteur IA
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="space-y-1">
            {MOCK_VISIBILITY.map((engine) => (
              <div key={engine.engine} className="flex items-center justify-between py-3 px-3 rounded-xl hover:bg-white/5 transition-colors">
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 rounded-xl bg-white/5 flex items-center justify-center text-xs font-bold text-white/60">
                    {engine.engine.substring(0, 2)}
                  </div>
                  <div>
                    <p className="font-medium text-white">{engine.engine}</p>
                    <p className="text-xs text-white/40">{engine.mentions} mentions - {engine.lastChecked}</p>
                  </div>
                </div>
                <div className="flex items-center gap-6">
                  <TrendIndicator value={engine.trend} />
                  <div className="text-right">
                    <p className="text-xl font-bold"><ScoreColor score={engine.score} /></p>
                  </div>
                  {/* Progress bar */}
                  <div className="w-24 h-2 bg-white/5 rounded-full overflow-hidden">
                    <div
                      className={`h-full rounded-full transition-all ${
                        engine.score >= 70 ? "bg-emerald-500" : engine.score >= 50 ? "bg-amber-500" : "bg-red-500"
                      }`}
                      style={{ width: `${engine.score}%` }}
                    />
                  </div>
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import { useState } from "react";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { EmptyState } from "@/components/ui/empty-state";
import {
  Lightbulb,
  CheckCircle2,
  Clock,
  ArrowUpRight,
  Zap,
  AlertTriangle,
  Info,
} from "lucide-react";

interface Rec {
  id: string;
  priority: "critical" | "high" | "medium" | "low";
  title: string;
  description: string;
  action: string;
  effort: "low" | "medium" | "high";
  impact: "low" | "medium" | "high";
  category: string;
  status: "open" | "in_progress" | "done";
}

// Mock data вҖ” will come from Supabase recommendations table
const MOCK_RECS: Rec[] = [
  {
    id: "1",
    priority: "critical",
    title: "Ajouter du Schema.org Organization",
    description: "Votre site n'a pas de balisage Schema.org. Les moteurs IA s'appuient fortement sur les donnees structurees pour comprendre votre entite.",
    action: "Generer et implementer le Schema.org Organization + WebSite",
    effort: "low",
    impact: "high",
    category: "Donnees structurees",
    status: "open",
  },
  {
    id: "2",
    priority: "high",
    title: "Optimiser le robots.txt pour les bots IA",
    description: "Votre robots.txt bloque certains crawlers IA (GPTBot, ClaudeBot). Cela empeche les moteurs IA d'indexer votre contenu.",
    action: "Mettre a jour le robots.txt pour autoriser les bots IA",
    effort: "low",
    impact: "high",
    category: "Technique",
    status: "open",
  },
  {
    id: "3",
    priority: "medium",
    title: "Creer une page FAQ structuree",
    description: "Les FAQs sont une source privilegiee pour les reponses IA. Ajoutez une page FAQ avec balisage FAQPage.",
    action: "Creer une page /faq avec Schema.org FAQPage",
    effort: "medium",
    impact: "high",
    category: "Contenu",
    status: "in_progress",
  },
  {
    id: "4",
    priority: "low",
    title: "Ameliorer les meta descriptions",
    description: "Vos meta descriptions sont generiques. Des descriptions plus specifiques aident les IA a comprendre le contenu de chaque page.",
    action: "Recrire les meta descriptions avec des mots-cles AEO",
    effort: "medium",
    impact: "medium",
    category: "SEO/AEO",
    status: "done",
  },
];

const PRIORITY_CONFIG: Record<string, { icon: React.ElementType; color: string; label: string; variant: "destructive" | "warning" | "default" | "secondary" }> = {
  critical: { icon: AlertTriangle, color: "text-red-400", label: "Critique", variant: "destructive" },
  high: { icon: Zap, color: "text-orange-400", label: "Haute", variant: "warning" },
  medium: { icon: Info, color: "text-blue-400", label: "Moyenne", variant: "default" },
  low: { icon: Info, color: "text-white/40", label: "Basse", variant: "secondary" },
};

const STATUS_CONFIG: Record<string, { label: string; variant: "secondary" | "default" | "success" }> = {
  open: { label: "A faire", variant: "secondary" },
  in_progress: { label: "En cours", variant: "default" },
  done: { label: "Termine", variant: "success" },
};

export default function RecommendationsPage() {
  const [filter, setFilter] = useState<string>("all");

  const filtered = filter === "all"
    ? MOCK_RECS
    : MOCK_RECS.filter((r) => r.status === filter);

  const openCount = MOCK_RECS.filter((r) => r.status === "open").length;
  const doneCount = MOCK_RECS.filter((r) => r.status === "done").length;

  return (
    <div>
      <div className="flex justify-between items-center mb-8">
        <h2 className="text-2xl font-serif font-bold text-white">Recommandations</h2>
        <div className="flex gap-2">
          {[
            { id: "all", label: "Toutes" },
            { id: "open", label: "A faire" },
            { id: "in_progress", label: "En cours" },
            { id: "done", label: "Terminees" },
          ].map((f) => (
            <button
              key={f.id}
              onClick={() => setFilter(f.id)}
              className={`px-3 py-1.5 text-xs font-medium rounded-lg transition-colors ${
                filter === f.id
                  ? "bg-primary/10 text-primary"
                  : "text-white/40 hover:text-white/70 hover:bg-white/5"
              }`}
            >
              {f.label}
            </button>
          ))}
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-3 gap-4 mb-8">
        <Card className="p-5">
          <p className="text-xs text-white/40 uppercase mb-1">A traiter</p>
          <p className="text-3xl font-bold text-amber-400">{openCount}</p>
        </Card>
        <Card className="p-5">
          <p className="text-xs text-white/40 uppercase mb-1">Terminees</p>
          <p className="text-3xl font-bold text-emerald-400">{doneCount}</p>
        </Card>
        <Card className="p-5">
          <p className="text-xs text-white/40 uppercase mb-1">Progression</p>
          <p className="text-3xl font-bold text-white">{MOCK_RECS.length > 0 ? Math.round((doneCount / MOCK_RECS.length) * 100) : 0}%</p>
        </Card>
      </div>

      {/* Recommendations List */}
      <div className="space-y-3">
        {filtered.map((rec) => {
          const priority = PRIORITY_CONFIG[rec.priority];
          const status = STATUS_CONFIG[rec.status];
          const PriorityIcon = priority.icon;

          return (
            <Card key={rec.id} className="p-5">
              <div className="flex items-start justify-between mb-3">
                <div className="flex items-center gap-3">
                  <PriorityIcon size={18} className={priority.color} />
                  <h3 className="font-semibold text-white">{rec.title}</h3>
                </div>
                <div className="flex items-center gap-2">
                  <Badge variant={priority.variant}>{priority.label}</Badge>
                  <Badge variant={status.variant}>{status.label}</Badge>
                </div>
              </div>
              <p className="text-sm text-white/50 mb-3 ml-8">{rec.description}</p>
              <div className="flex items-center justify-between ml-8">
                <div className="flex items-center gap-4 text-xs text-white/30">
                  <span className="flex items-center gap-1">
                    <Clock size={12} /> Effort: {rec.effort}
                  </span>
                  <span className="flex items-center gap-1">
                    <ArrowUpRight size={12} /> Impact: {rec.impact}
                  </span>
                  <span>{rec.category}</span>
                </div>
                {rec.status !== "done" && (
                  <Button size="sm" variant="outline">
                    Generer la solution
                  </Button>
                )}
              </div>
            </Card>
          );
        })}
      </div>
    </div>
  );
}

