"use client"

import React, { createContext, useContext, useEffect, useState } from "react"
import { MOCK_WORKSPACE } from "./mock-data"

interface WorkspaceData {
  id: string
  name: string
  slug: string
  plan: string
  plan_status: string
  credits_remaining: number
  role: string
}

interface WorkspaceContextValue {
  workspace: WorkspaceData | null
  isLoading: boolean
  reload: () => void
}

const WorkspaceContext = createContext<WorkspaceContextValue>({
  workspace: null,
  isLoading: true,
  reload: () => {},
})

function shouldUseMockAuth(): boolean {
  if (typeof window === 'undefined') return true
  const url = process.env.NEXT_PUBLIC_SUPABASE_URL
  const key = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY
  return !url || url === 'https://placeholder.supabase.co' || !key || key === 'placeholder'
}

export function WorkspaceProvider({ children }: { children: React.ReactNode }) {
  const [workspace, setWorkspace] = useState<WorkspaceData | null>(null)
  const [isLoading, setIsLoading] = useState(true)

  const loadWorkspace = async () => {
    // If no Supabase, use mock workspace
    if (shouldUseMockAuth()) {
      setWorkspace(MOCK_WORKSPACE)
      setIsLoading(false)
      return
    }

    try {
      const { createClient } = await import("@/lib/supabase/client")
      const supabase = createClient()
      const { data: { user } } = await supabase.auth.getUser()
      if (!user) {
        setWorkspace(MOCK_WORKSPACE)
        setIsLoading(false)
        return
      }

      const { data, error } = await supabase
        .from("workspace_users")
        .select("role, workspaces(id, name, slug, plan, plan_status, credits_remaining)")
        .eq("user_id", user.id)
        .limit(1)
        .single()

      if (error || !data) {
        setWorkspace(MOCK_WORKSPACE)
        setIsLoading(false)
        return
      }

      const ws = data.workspaces as unknown as Record<string, unknown>
      setWorkspace({
        id: ws.id as string,
        name: ws.name as string,
        slug: ws.slug as string,
        plan: ws.plan as string,
        plan_status: ws.plan_status as string,
        credits_remaining: ws.credits_remaining as number,
        role: data.role,
      })
    } catch {
      setWorkspace(MOCK_WORKSPACE)
    } finally {
      setIsLoading(false)
    }
  }

  useEffect(() => {
    loadWorkspace()
  }, [])

  return (
    <WorkspaceContext.Provider value={{ workspace, isLoading, reload: loadWorkspace }}>
      {children}
    </WorkspaceContext.Provider>
  )
}

export function useWorkspace() {
  return useContext(WorkspaceContext)
}

