      <div className="flex justify-between items-start mb-3">
        <div>
          <p className="text-xs text-white/40 uppercase tracking-wide">{label}</p>
          <h3 className="text-3xl font-bold mt-1 text-white">
            {value}
            {suffix && <span className="text-sm text-white/30">{suffix}</span>}
          </h3>
        </div>
        {icon && (
          <div className="p-2.5 bg-primary/10 rounded-xl text-primary">
            {icon}
          </div>
        )}
      </div>
      {change !== undefined && (
        <span className={cn(
          "text-xs font-medium flex items-center gap-1",
          change >= 0 ? "text-emerald-400" : "text-red-400"
        )}>
          {change >= 0 ? <ArrowUpRight size={12} /> : <ArrowDownRight size={12} />}
          {change >= 0 ? '+' : ''}{change}%
          {changeLabel && <span className="text-white/30">{changeLabel}</span>}
        </span>
      )}
    </Card>
  );
}

