"use client"

import React, { useState } from 'react';
import { Copy, Check } from 'lucide-react';
import { cn } from '@/lib/utils';

interface CodeBlockProps {
  code: string;
  language?: string;
  title?: string;
  className?: string;
}

export function CodeBlock({ code, language, title, className }: CodeBlockProps) {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className={cn("rounded-xl border border-white/10 overflow-hidden", className)}>
      {(title || language) && (
        <div className="flex items-center justify-between px-4 py-2.5 bg-white/[0.03] border-b border-white/5">
          <div className="flex items-center gap-2">
            {title && <span className="text-xs font-medium text-white/60">{title}</span>}
            {language && (
              <span className="text-[10px] px-2 py-0.5 bg-white/5 rounded-full text-white/40 uppercase">{language}</span>
            )}
          </div>
          <button
            onClick={handleCopy}
            className="flex items-center gap-1.5 px-2 py-1 rounded-lg text-xs text-white/40 hover:text-white/70 hover:bg-white/5 transition-colors"
          >
            {copied ? <Check size={12} className="text-emerald-400" /> : <Copy size={12} />}
            {copied ? 'Copie !' : 'Copier'}
          </button>
        </div>
      )}
      <pre className="p-4 overflow-x-auto bg-[#0d0f12]">
        <code className="text-sm text-white/70 font-mono leading-relaxed whitespace-pre">
          {code}
        </code>
      </pre>
    </div>
  );
}

