'use client';
import React, { useState } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { Loader2, ArrowRight, Sparkles } from 'lucide-react';

function shouldUseMockAuth(): boolean {
  const url = process.env.NEXT_PUBLIC_SUPABASE_URL;
  const key = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;
  return !url || url === 'https://placeholder.supabase.co' || !key || key === 'placeholder';
}

export default function LoginPage() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const router = useRouter();
  const isMock = shouldUseMockAuth();

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    if (isMock) {
      await new Promise((r) => setTimeout(r, 500));
      router.push('/app');
      return;
    }

    try {
      const { createClient } = await import('@/lib/supabase/client');
      const supabase = createClient();
      const { error } = await supabase.auth.signInWithPassword({ email, password });

      if (error) {
        setError(error.message);
        setLoading(false);
      } else {
        router.push('/app');
        router.refresh();
      }
    } catch {
      setError('Erreur de connexion');
      setLoading(false);
    }
  };

  const handleMockLogin = () => {
    setLoading(true);
    setTimeout(() => {
      router.push('/app');
    }, 300);
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4">
      <div className="w-full max-w-md">
        {/* Logo */}
        <div className="flex items-center justify-center gap-2.5 mb-8">
          <div className="w-10 h-10 rounded-xl bg-primary flex items-center justify-center text-black font-serif font-bold text-xl">
            C
          </div>
          <span className="font-bold text-xl text-white">CitedBy.ai</span>
        </div>

        <div className="bg-white/5 backdrop-blur-xl border border-white/10 rounded-2xl p-8">
          <h1 className="text-2xl font-serif font-bold mb-1 text-center text-white">Connexion</h1>
          <p className="text-white/40 text-center mb-8 text-sm">Accedez a votre espace CitedBy</p>

          {error && (
            <div className="bg-red-500/10 border border-red-500/20 text-red-400 p-3 rounded-xl mb-4 text-sm">
              {error}
            </div>
          )}

          {isMock && (
            <button
              onClick={handleMockLogin}
              disabled={loading}
              className="w-full mb-4 px-4 py-3 bg-primary/10 border border-primary/20 text-primary font-medium rounded-xl hover:bg-primary/20 transition-colors flex items-center justify-center gap-2 text-sm"
            >
              <Sparkles size={16} />
              Acces demo (sans compte)
              <ArrowRight size={14} />
            </button>
          )}

          {isMock && (
            <div className="flex items-center gap-3 mb-4">
              <div className="flex-1 h-px bg-white/10" />
              <span className="text-xs text-white/30">ou</span>
              <div className="flex-1 h-px bg-white/10" />
            </div>
          )}

          <form onSubmit={handleLogin} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-white/70 mb-1.5">Email</label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full bg-white/5 border border-white/10 rounded-xl p-3 text-white placeholder:text-white/30 focus:border-primary/50 focus:ring-2 focus:ring-primary/20 outline-none transition-all text-sm"
                placeholder="vous@entreprise.com"
                required={!isMock}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-white/70 mb-1.5">Mot de passe</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full bg-white/5 border border-white/10 rounded-xl p-3 text-white placeholder:text-white/30 focus:border-primary/50 focus:ring-2 focus:ring-primary/20 outline-none transition-all text-sm"
                placeholder="вҖўвҖўвҖўвҖўвҖўвҖўвҖўвҖў"
                required={!isMock}
              />
            </div>
            <button
              type="submit"
              disabled={loading}
              className="w-full bg-primary text-black font-bold py-3 rounded-xl hover:bg-emerald-400 transition-all flex items-center justify-center text-sm"
            >
              {loading ? <Loader2 className="animate-spin" size={18} /> : 'Se connecter'}
            </button>
          </form>

          <p className="mt-6 text-center text-sm text-white/40">
            Pas encore de compte ?{' '}
            <Link href="/register" className="text-primary hover:text-primary/80 font-medium">
              S&apos;inscrire
            </Link>
          </p>
        </div>
      </div>
    </div>
  );
}

