import React, { useState, useRef, useEffect } from 'react';
import { Globe } from 'lucide-react';
import { useTranslation } from './context';
import { SUPPORTED_LOCALES, Locale } from './types';

// ================================================================
// LANGUAGE SELECTOR вҖ” Dropdown sГ©lecteur de langue
// Styles : glass-panel, cohГ©rent avec le design CitedBy.ai
// ================================================================

interface LanguageSelectorProps {
  /** Compact mode : affiche uniquement le drapeau + code (pour la navbar) */
  compact?: boolean;
  /** Classe CSS additionnelle */
  className?: string;
}

export const LanguageSelector: React.FC<LanguageSelectorProps> = ({ compact = false, className = '' }) => {
  const { locale, setLocale } = useTranslation();
  const [isOpen, setIsOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  const currentLocale = SUPPORTED_LOCALES.find(l => l.code === locale)!;

  // Close dropdown on outside click
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (ref.current && !ref.current.contains(e.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSelect = (code: Locale) => {
    setLocale(code);
    setIsOpen(false);
  };

  return (
    <div ref={ref} className={`relative ${className}`}>
      {/* Trigger button */}
      <button
        onClick={() => setIsOpen(!isOpen)}
        className={`flex items-center gap-2 rounded-lg border border-white/10 transition-all hover:border-primary/50 hover:bg-primary/10 group ${
          compact
            ? 'px-2.5 py-1.5 bg-white/5'
            : 'px-3 py-2 bg-[#1a1d21]'
        }`}
        title={`Language: ${currentLocale.nativeName}`}
      >
        <span className="text-base leading-none">{currentLocale.flag}</span>
        {compact ? (
          <span className="text-xs font-bold text-gray-300 group-hover:text-primary uppercase">{currentLocale.code}</span>
        ) : (
          <>
            <span className="text-sm font-medium text-gray-300 group-hover:text-white">{currentLocale.nativeName}</span>
            <Globe size={14} className="text-gray-500 group-hover:text-primary" />
          </>
        )}
      </button>

      {/* Dropdown */}
      {isOpen && (
        <div className="absolute top-full mt-2 right-0 z-[100] min-w-[180px] bg-[#0f1115] border border-white/10 rounded-xl shadow-2xl shadow-black/50 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
          {SUPPORTED_LOCALES.map((loc) => (
            <button
              key={loc.code}
              onClick={() => handleSelect(loc.code)}
              className={`w-full flex items-center gap-3 px-4 py-3 text-left transition-all ${
                locale === loc.code
                  ? 'bg-primary/10 text-primary border-l-2 border-primary'
                  : 'text-gray-400 hover:bg-white/5 hover:text-white border-l-2 border-transparent'
              }`}
            >
              <span className="text-lg leading-none">{loc.flag}</span>
              <div className="flex flex-col">
                <span className="text-sm font-medium">{loc.nativeName}</span>
                <span className="text-[10px] text-gray-500 uppercase">{loc.name}</span>
              </div>
              {locale === loc.code && (
                <span className="ml-auto text-primary text-xs">&#10003;</span>
              )}
            </button>
          ))}
        </div>
      )}
    </div>
  );
};

export default LanguageSelector;

import { createClient } from "@/lib/supabase/client"
import type { DBProject, AnalysisRun, DBRecommendation, GeneratedContentRow } from "@/lib/db"

// ============================================================
// Client-side database helpers (for 'use client' components)
// Uses the browser Supabase client
// ============================================================

function getSupabase() {
  return createClient()
}

// Projects
export async function getProjectsClient(workspaceId: string) {
  const supabase = getSupabase()
  const { data, error } = await supabase
    .from("projects")
    .select("*")
    .eq("workspace_id", workspaceId)
    .order("created_at", { ascending: false })

  if (error) throw error
  return data as DBProject[]
}

export async function getProjectClient(projectId: string) {
  const supabase = getSupabase()
  const { data, error } = await supabase
    .from("projects")
    .select("*")
    .eq("id", projectId)
    .single()

  if (error) throw error
  return data as DBProject
}

export async function createProjectClient(input: {
  workspace_id: string
  name: string
  domain: string
  brand_name?: string
  industry?: string
  competitors?: string[]
  keywords?: string[]
}) {
  const supabase = getSupabase()
  const { data, error } = await supabase
    .from("projects")
    .insert(input)
    .select()
    .single()

  if (error) throw error
  return data as DBProject
}

export async function deleteProjectClient(projectId: string) {
  const supabase = getSupabase()
  const { error } = await supabase
    .from("projects")
    .delete()
    .eq("id", projectId)

  if (error) throw error
}

// Analysis Runs
export async function getProjectRunsClient(projectId: string, limit = 10) {
  const supabase = getSupabase()
  const { data, error } = await supabase
    .from("analysis_runs")
    .select("*")
    .eq("project_id", projectId)
    .order("created_at", { ascending: false })
    .limit(limit)

  if (error) throw error
  return data as AnalysisRun[]
}

export async function getRunResultsClient(runId: string) {
  const supabase = getSupabase()
  const { data, error } = await supabase
    .from("run_results")
    .select("*")
    .eq("run_id", runId)

  if (error) throw error
  return data
}

// Recommendations
export async function getProjectRecommendationsClient(projectId: string) {
  const supabase = getSupabase()
  const { data, error } = await supabase
    .from("recommendations")
    .select("*")
    .eq("project_id", projectId)
    .order("priority", { ascending: true })

  if (error) throw error
  return data as DBRecommendation[]
}

export async function updateRecommendationStatusClient(recId: string, status: string) {
  const supabase = getSupabase()
  const { error } = await supabase
    .from("recommendations")
    .update({ status })
    .eq("id", recId)

  if (error) throw error
}

// Generated Contents
export async function getProjectContentsClient(projectId: string) {
  const supabase = getSupabase()
  const { data, error } = await supabase
    .from("generated_contents")
    .select("*")
    .eq("project_id", projectId)
    .order("created_at", { ascending: false })

  if (error) throw error
  return data as GeneratedContentRow[]
}

// Content status update
export async function updateContentStatusClient(
  contentId: string,
  status: string
) {
  const supabase = getSupabase()
  const { error } = await supabase
    .from("generated_contents")
    .update({ status })
    .eq("id", contentId)

  if (error) throw error
}

// User Workspace
export async function getUserWorkspaceClient() {
  const supabase = getSupabase()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return null

  const { data, error } = await supabase
    .from("workspace_users")
    .select("workspace_id, role, workspaces(*)")
    .eq("user_id", user.id)
    .limit(1)
    .single()

  if (error && error.code !== "PGRST116") throw error
  return data as { workspace_id: string; role: string; workspaces: Record<string, unknown> } | null
}

