'use client';

import { useState } from 'react';
import {
  FileText,
  HelpCircle,
  BookOpen,
  ClipboardList,
  Loader2,
  Copy,
  Check,
  Sparkles,
} from 'lucide-react';
import { PageHeader } from '@/components/page-header';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/components/ui/tabs';
import { MOCK_SMC_CONTENTS } from '@/lib/mock-data';

const TOOLS = [
  {
    id: 'fiche',
    label: 'Fiche Entreprise',
    icon: FileText,
    description: 'Generez une fiche entreprise complete optimisee pour etre citee par les IA.',
    color: 'text-blue-400',
    bg: 'bg-blue-500/10',
  },
  {
    id: 'faq',
    label: 'FAQ Optimisee',
    icon: HelpCircle,
    description: 'Creez des FAQs structurees que les moteurs IA peuvent facilement extraire.',
    color: 'text-emerald-400',
    bg: 'bg-emerald-500/10',
  },
  {
    id: 'article',
    label: 'Article AEO',
    icon: BookOpen,
    description: 'Redigez un article optimise pour apparaitre dans les reponses des IA.',
    color: 'text-purple-400',
    bg: 'bg-purple-500/10',
  },
];

export default function SMCStudioPage() {
  const [activeTab, setActiveTab] = useState('studio');
  const [selectedTool, setSelectedTool] = useState<string | null>(null);
  const [brandName, setBrandName] = useState('');
  const [brandDescription, setBrandDescription] = useState('');
  const [generating, setGenerating] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  const handleGenerate = () => {
    if (!brandName) return;
    setGenerating(true);
    setTimeout(() => {
      const mockContent = MOCK_SMC_CONTENTS.find((c) => c.type === selectedTool);
      setResult(mockContent?.content || 'Contenu genere avec succes.');
      setGenerating(false);
    }, 2000);
  };

  const handleCopy = () => {
    if (result) {
      navigator.clipboard.writeText(result);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  return (
    <div className="p-4 sm:p-8 max-w-7xl mx-auto">
      <PageHeader
        title="SMC Studio"
        description="Generez du contenu structure optimise pour les moteurs IA (fiches, FAQ, articles)."
        breadcrumbs={[
          { label: 'App', href: '/app' },
          { label: 'Outils Generatifs', href: '/app/generative-tools' },
          { label: 'SMC Studio' },
        ]}
      />

      <Tabs value={activeTab} onValueChange={setActiveTab}>
        <TabsList>
          <TabsTrigger value="studio">
            <Sparkles size={14} className="mr-1.5" />
            Studio
          </TabsTrigger>
          <TabsTrigger value="library">
            <ClipboardList size={14} className="mr-1.5" />
            Bibliotheque ({MOCK_SMC_CONTENTS.length})
          </TabsTrigger>
        </TabsList>

        <TabsContent value="studio">
          <div className="mt-6 space-y-6 animate-fade-in-up">
            {/* Tool Selection */}
            {!selectedTool ? (
              <div className="grid md:grid-cols-3 gap-4">
                {TOOLS.map((tool) => {
                  const Icon = tool.icon;
                  return (
                    <button
                      key={tool.id}
                      onClick={() => setSelectedTool(tool.id)}
                      className="group text-left bg-white/[0.02] border border-white/10 rounded-2xl p-6 hover:bg-white/[0.05] hover:border-white/20 transition-all"
                    >
                      <div className={`w-12 h-12 rounded-xl ${tool.bg} flex items-center justify-center ${tool.color} mb-4 group-hover:scale-110 transition-transform`}>
                        <Icon size={24} />
                      </div>
                      <h3 className="text-white font-bold mb-2">{tool.label}</h3>
                      <p className="text-sm text-white/40">{tool.description}</p>
                    </button>
                  );
                })}
              </div>
            ) : (
              <div className="space-y-6">
                {/* Back Button */}
                <button
                  onClick={() => { setSelectedTool(null); setResult(null); }}
                  className="text-sm text-white/40 hover:text-white transition-colors"
                >
                  &larr; Retour au choix d'outil
                </button>

                <Card className="p-6">
                  <div className="flex items-center gap-3 mb-6">
                    {(() => {
                      const tool = TOOLS.find((t) => t.id === selectedTool);
                      const Icon = tool?.icon || FileText;
                      return (
                        <>
                          <div className={`w-10 h-10 rounded-xl ${tool?.bg} flex items-center justify-center ${tool?.color}`}>
                            <Icon size={20} />
                          </div>
                          <div>
                            <h3 className="text-lg font-bold text-white">{tool?.label}</h3>
                            <p className="text-sm text-white/40">{tool?.description}</p>
                          </div>
                        </>
                      );
                    })()}
                  </div>

                  <div className="space-y-4">
                    <div>
                      <label className="block text-sm font-medium text-white/70 mb-1.5">Nom de la marque *</label>
                      <input
                        type="text"
                        value={brandName}
                        onChange={(e) => setBrandName(e.target.value)}
                        className="w-full bg-white/5 border border-white/10 rounded-xl p-3 text-white placeholder:text-white/30 focus:border-primary/50 focus:ring-2 focus:ring-primary/20 outline-none transition-all text-sm"
                        placeholder="Ex: CitedBy.ai"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-white/70 mb-1.5">Description de l'activite</label>
                      <textarea
                        value={brandDescription}
                        onChange={(e) => setBrandDescription(e.target.value)}
                        rows={3}
                        className="w-full bg-white/5 border border-white/10 rounded-xl p-3 text-white placeholder:text-white/30 focus:border-primary/50 focus:ring-2 focus:ring-primary/20 outline-none transition-all text-sm resize-none"
                        placeholder="Decrivez votre entreprise, vos produits ou services..."
                      />
                    </div>
                    <Button
                      onClick={handleGenerate}
                      disabled={!brandName || generating}
                      className="gap-2"
                    >
                      {generating ? (
                        <><Loader2 size={16} className="animate-spin" /> Generation en cours...</>
                      ) : (
                        <><Sparkles size={16} /> Generer</>
                      )}
                    </Button>
                  </div>
                </Card>

                {/* Result */}
                {result && (
                  <Card className="p-6 animate-fade-in-up">
                    <div className="flex items-center justify-between mb-4">
                      <h3 className="text-lg font-bold text-white">Resultat</h3>
                      <Button variant="outline" size="sm" onClick={handleCopy} className="gap-2">
                        {copied ? <><Check size={14} /> Copie !</> : <><Copy size={14} /> Copier</>}
                      </Button>
                    </div>
                    <div className="bg-white/[0.02] border border-white/5 rounded-xl p-4">
                      <pre className="text-sm text-white/70 whitespace-pre-wrap font-sans leading-relaxed">
                        {result}
                      </pre>
                    </div>
                  </Card>
                )}
              </div>
            )}
          </div>
        </TabsContent>

        <TabsContent value="library">
          <div className="mt-6 space-y-4 animate-fade-in-up">
            {MOCK_SMC_CONTENTS.map((content) => {
              const typeColors: Record<string, string> = {
                fiche: 'bg-blue-500/10 text-blue-400',
                faq: 'bg-emerald-500/10 text-emerald-400',
                article: 'bg-purple-500/10 text-purple-400',
                brief: 'bg-amber-500/10 text-amber-400',
              };

              return (
                <Card key={content.id} className="p-5">
                  <div className="flex items-start justify-between gap-4 mb-3">
                    <div>
                      <div className="flex items-center gap-2 mb-1">
                        <Badge className={typeColors[content.type]}>{content.type}</Badge>
                        <h3 className="text-sm font-bold text-white">{content.title}</h3>
                      </div>
                      <p className="text-xs text-white/30">
                        {new Date(content.timestamp).toLocaleDateString('fr-FR')}
                      </p>
                    </div>
                  </div>
                  <p className="text-sm text-white/50 line-clamp-3">{content.content}</p>
                </Card>
              );
            })}
          </div>
        </TabsContent>
      </Tabs>
    </div>
  );
}

