                  <div className="flex items-center gap-3 mb-6">
                    {(() => {
                      const tool = TOOLS.find((t) => t.id === selectedTool);
                      const Icon = tool?.icon || FileText;
                      return (
                        <>
                          <div className={`w-10 h-10 rounded-xl ${tool?.bg} flex items-center justify-center ${tool?.color}`}>
                            <Icon size={20} />
                          </div>
                          <div>
                            <h3 className="text-lg font-bold text-white">{tool?.label}</h3>
                            <p className="text-sm text-white/40">{tool?.description}</p>
                          </div>
                        </>
                      );
                    })()}
                  </div>

                  <div className="space-y-4">
                    <div>
                      <label className="block text-sm font-medium text-white/70 mb-1.5">Nom de la marque *</label>
                      <input
                        type="text"
                        value={brandName}
                        onChange={(e) => setBrandName(e.target.value)}
                        className="w-full bg-white/5 border border-white/10 rounded-xl p-3 text-white placeholder:text-white/30 focus:border-primary/50 focus:ring-2 focus:ring-primary/20 outline-none transition-all text-sm"
                        placeholder="Ex: CitedBy.ai"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-white/70 mb-1.5">Description de l'activite</label>
                      <textarea
                        value={brandDescription}
                        onChange={(e) => setBrandDescription(e.target.value)}
                        rows={3}
                        className="w-full bg-white/5 border border-white/10 rounded-xl p-3 text-white placeholder:text-white/30 focus:border-primary/50 focus:ring-2 focus:ring-primary/20 outline-none transition-all text-sm resize-none"
                        placeholder="Decrivez votre entreprise, vos produits ou services..."
                      />
                    </div>
                    <Button
                      onClick={handleGenerate}
                      disabled={!brandName || generating}
                      className="gap-2"
                    >
                      {generating ? (
                        <><Loader2 size={16} className="animate-spin" /> Generation en cours...</>
                      ) : (
                        <><Sparkles size={16} /> Generer</>
                      )}
                    </Button>
                  </div>
                </Card>

                {/* Result */}
                {result && (
                  <Card className="p-6 animate-fade-in-up">
                    <div className="flex items-center justify-between mb-4">
                      <h3 className="text-lg font-bold text-white">Resultat</h3>
                      <Button variant="outline" size="sm" onClick={handleCopy} className="gap-2">
                        {copied ? <><Check size={14} /> Copie !</> : <><Copy size={14} /> Copier</>}
                      </Button>
                    </div>
                    <div className="bg-white/[0.02] border border-white/5 rounded-xl p-4">
                      <pre className="text-sm text-white/70 whitespace-pre-wrap font-sans leading-relaxed">
                        {result}
                      </pre>
                    </div>
                  </Card>
                )}
              </div>
            )}
          </div>
        </TabsContent>

        <TabsContent value="library">
          <div className="mt-6 space-y-4 animate-fade-in-up">
            {MOCK_SMC_CONTENTS.map((content) => {
              const typeColors: Record<string, string> = {
                fiche: 'bg-blue-500/10 text-blue-400',
                faq: 'bg-emerald-500/10 text-emerald-400',
                article: 'bg-purple-500/10 text-purple-400',
                brief: 'bg-amber-500/10 text-amber-400',
              };

              return (
                <Card key={content.id} className="p-5">
                  <div className="flex items-start justify-between gap-4 mb-3">
                    <div>
                      <div className="flex items-center gap-2 mb-1">
                        <Badge className={typeColors[content.type]}>{content.type}</Badge>
                        <h3 className="text-sm font-bold text-white">{content.title}</h3>
                      </div>
                      <p className="text-xs text-white/30">
                        {new Date(content.timestamp).toLocaleDateString('fr-FR')}
                      </p>
                    </div>
                  </div>
                  <p className="text-sm text-white/50 line-clamp-3">{content.content}</p>
                </Card>
              );
            })}
          </div>
        </TabsContent>
      </Tabs>
    </div>
  );
}

input.content:
'use client';

import { useState } from 'react';
import {
  FileText,
  HelpCircle,
  BookOpen,
  Briefcase,
  Copy,
  Check,
  Loader2,
  Sparkles,
  Clock,
} from 'lucide-react';
import { PageHeader } from '@/components/page-header';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/components/ui/tabs';
import { MOCK_SMC_CONTENTS } from '@/lib/mock-data';

const TOOLS = [
  {
    id: 'fiche',
    label: 'Fiche Entreprise',
    description: 'Generez une fiche optimisee pour les IA avec vos informations cles.',
    icon: Briefcase,
    color: 'text-blue-400',
    bg: 'bg-blue-500/10',
  },
  {
    id: 'faq',
    label: 'FAQ Optimisee',
    description: 'Creez une FAQ structuree avec Schema.org FAQPage.',
    icon: HelpCircle,
    color: 'text-purple-400',
    bg: 'bg-purple-500/10',
  },
  {
    id: 'article',
    label: 'Article AEO',
    description: 'Redigez un article optimise pour etre cite par les IA.',
    icon: BookOpen,
    color: 'text-emerald-400',
    bg: 'bg-emerald-500/10',
  },
];

export default function SMCStudioPage() {
  const [activeTab, setActiveTab] = useState('studio');
  const [selectedTool, setSelectedTool] = useState<string | null>(null);
  const [topic, setTopic] = useState('');
  const [generating, setGenerating] = useState(false);
  const [generatedContent, setGeneratedContent] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  const handleGenerate = () => {
    if (!selectedTool || !topic) return;
    setGenerating(true);
    setGeneratedContent(null);

    setTimeout(() => {
      const mockResults: Record<string, string> = {
        fiche: `# Fiche Entreprise вҖ” ${topic}\n\n## Description\n${topic} est une entreprise innovante specialisee dans son domaine d'activite. Fondee pour repondre aux besoins croissants du marche, elle accompagne ses clients avec des solutions sur mesure.\n\n## Services principaux\n- Conseil strategique et accompagnement\n- Solutions technologiques innovantes\n- Formation et certification\n- Support technique 24/7\n\n## Chiffres cles\n- +500 clients actifs\n- 98% de satisfaction client\n- Present dans 3 pays\n- Equipe de 45 experts`,
        faq: `# FAQ вҖ” ${topic}\n\n## Q: Qu'est-ce que ${topic} ?\nR: ${topic} est une solution complete qui permet aux entreprises d'optimiser leur presence digitale et d'ameliorer leur visibilite aupres des moteurs de reponse IA.\n\n## Q: Comment fonctionne ${topic} ?\nR: ${topic} utilise une technologie proprietaire d'analyse et d'optimisation pour evaluer et ameliorer votre contenu.\n\n## Q: Quels sont les tarifs ?\nR: ${topic} propose plusieurs formules adaptees a chaque besoin, a partir de 49вӮ¬/mois pour le plan Starter.`,
        article: `# ${topic} : Guide Complet pour 2024\n\nDans un monde ou l'IA transforme la maniere dont les utilisateurs cherchent l'information, ${topic} devient un enjeu strategique pour les entreprises.\n\n## Pourquoi c'est important\nLes moteurs de reponse IA comme ChatGPT, Perplexity et Gemini citent de plus en plus de sources dans leurs reponses. Etre cite signifie gagner en visibilite et en credibilite.\n\n## Les 5 strategies cles\n1. **Structurer son contenu** avec des reponses directes\n2. **Utiliser le Schema.org** pour enrichir les donnees\n3. **Creer des FAQ** extractibles par les IA\n4. **Optimiser le robots.txt** pour les bots IA\n5. **Monitorer les citations** avec des outils dedies`,
      };
      setGeneratedContent(mockResults[selectedTool] || '');
      setGenerating(false);
    }, 2000);
  };

  const handleCopy = () => {
    if (generatedContent) {
      navigator.clipboard.writeText(generatedContent);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  return (
    <div className="p-4 sm:p-8 max-w-7xl mx-auto">
      <PageHeader
        title="SMC Studio"
        description="Generez des contenus strategiques optimises pour les moteurs de reponse IA."
        breadcrumbs={[
          { label: 'App', href: '/app' },
          { label: 'Outils Generatifs', href: '/app/generative-tools' },
          { label: 'SMC Studio' },
        ]}
      />

      <Tabs value={activeTab} onValueChange={setActiveTab}>
        <TabsList className="mb-8">
          <TabsTrigger value="studio">Studio</TabsTrigger>
          <TabsTrigger value="library">Bibliotheque ({MOCK_SMC_CONTENTS.length})</TabsTrigger>
        </TabsList>

        <TabsContent value="studio">
          <div className="grid lg:grid-cols-12 gap-8 animate-fade-in-up">
            {/* Tool Selection */}
            <div className="lg:col-span-5 space-y-4">
              <h3 className="text-sm font-medium text-white/50 uppercase tracking-wider mb-3">
                Choisissez un outil
              </h3>
              {TOOLS.map((tool) => {
                const Icon = tool.icon;
                const isSelected = selectedTool === tool.id;
                return (
                  <button
                    key={tool.id}
                    onClick={() => setSelectedTool(tool.id)}
                    className={`w-full text-left p-4 rounded-xl border transition-all ${
                      isSelected
                        ? 'bg-primary/10 border-primary/30'
                        : 'bg-white/[0.02] border-white/10 hover:border-white/20 hover:bg-white/[0.04]'
                    }`}
                  >
                    <div className="flex items-center gap-3 mb-2">
                      <div className={`p-2 rounded-lg ${tool.bg}`}>
                        <Icon size={18} className={tool.color} />
                      </div>
                      <span className="font-medium text-white">{tool.label}</span>
                      {isSelected && <Badge variant="success" className="ml-auto text-[10px]">Selectionne</Badge>}
                    </div>
                    <p className="text-xs text-white/40 pl-11">{tool.description}</p>
                  </button>
                );
              })}

              {/* Input */}
              {selectedTool && (
                <div className="space-y-3 pt-4 animate-fade-in-up">
                  <label className="block text-sm font-medium text-white/70">
                    Sujet / Nom de l&apos;entreprise
                  </label>
                  <input
                    type="text"
                    value={topic}
                    onChange={(e) => setTopic(e.target.value)}
                    placeholder="Ex: CitedBy.ai, Mon entreprise..."
                    className="w-full bg-white/5 border border-white/10 rounded-xl p-3 text-white placeholder:text-white/30 focus:border-primary/50 focus:ring-2 focus:ring-primary/20 outline-none transition-all text-sm"
                  />
                  <Button
                    onClick={handleGenerate}
                    disabled={!topic || generating}
                    className="w-full gap-2"
                  >
                    {generating ? (
                      <>
                        <Loader2 className="animate-spin" size={16} />
                        Generation en cours...
                      </>
                    ) : (
                      <>
                        <Sparkles size={16} />
                        Generer
                      </>
                    )}
                  </Button>
                </div>
              )}
            </div>

            {/* Output */}
            <div className="lg:col-span-7">
              {generatedContent ? (
                <Card className="p-6 animate-fade-in-up">
                  <div className="flex items-center justify-between mb-4">
                    <div className="flex items-center gap-2">
                      <Sparkles size={16} className="text-primary" />
                      <span className="text-sm font-bold text-white">Contenu genere</span>
                    </div>
                    <Button variant="outline" size="sm" onClick={handleCopy} className="gap-1.5">
                      {copied ? <Check size={14} /> : <Copy size={14} />}
                      {copied ? 'Copie !' : 'Copier'}
                    </Button>
                  </div>
                  <div className="bg-white/[0.02] border border-white/5 rounded-xl p-5 max-h-[500px] overflow-y-auto">
                    <pre className="whitespace-pre-wrap text-sm text-white/70 font-sans leading-relaxed">
                      {generatedContent}
                    </pre>
                  </div>
                </Card>
              ) : (
                <div className="flex flex-col items-center justify-center h-full min-h-[400px] text-center">
                  <div className="w-16 h-16 rounded-2xl bg-white/5 flex items-center justify-center mb-4">
                    <FileText size={24} className="text-white/20" />
                  </div>
                  <p className="text-white/30 text-sm">
                    Selectionnez un outil et entrez un sujet pour generer du contenu
                  </p>
                </div>
              )}
            </div>
          </div>
        </TabsContent>

        <TabsContent value="library">
          <div className="space-y-4 animate-fade-in-up">
            {MOCK_SMC_CONTENTS.map((content) => {
              const typeIcons: Record<string, typeof FileText> = {
                fiche: Briefcase,
                faq: HelpCircle,
                article: BookOpen,
                brief: FileText,
              };
              const TypeIcon = typeIcons[content.type] || FileText;

              return (
                <Card key={content.id} className="p-5">
                  <div className="flex items-start gap-4">
                    <div className="p-2.5 rounded-xl bg-white/5 shrink-0">
                      <TypeIcon size={18} className="text-white/40" />
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <h3 className="text-sm font-bold text-white truncate">{content.title}</h3>
                        <Badge variant="secondary" className="text-[10px] shrink-0">{content.type}</Badge>
                      </div>
                      <p className="text-xs text-white/40 line-clamp-2 mb-2">{content.content}</p>
                      <div className="flex items-center gap-1.5 text-[10px] text-white/30">
                        <Clock size={10} />
                        {new Date(content.timestamp).toLocaleDateString('fr-FR')}
                      </div>
                    </div>
                  </div>
                </Card>
              );
            })}
          </div>
        </TabsContent>
      </Tabs>
    </div>
  );
}

'use client';

import { useState } from 'react';
import {
  PenTool,
  ArrowLeft,
  ArrowRight,
  Sparkles,
  Loader2,
  Copy,
  Check,
  ShoppingCart,
  Monitor,
  Building,
  UtensilsCrossed,
  Heart,
  DollarSign,
  Scale,
  GraduationCap,
  Globe,
} from 'lucide-react';
import { PageHeader } from '@/components/page-header';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import type { ContentVertical, ContentType } from '@/types';

const VERTICALS: { id: ContentVertical; label: string; icon: typeof Globe }[] = [
  { id: 'ecommerce', label: 'E-commerce', icon: ShoppingCart },
  { id: 'saas', label: 'SaaS', icon: Monitor },
  { id: 'immobilier', label: 'Immobilier', icon: Building },
  { id: 'restauration', label: 'Restauration', icon: UtensilsCrossed },
  { id: 'sante', label: 'Sante', icon: Heart },
  { id: 'finance', label: 'Finance', icon: DollarSign },
  { id: 'juridique', label: 'Juridique', icon: Scale },
  { id: 'education', label: 'Education', icon: GraduationCap },
  { id: 'general', label: 'General', icon: Globe },
];

const CONTENT_TYPES: { id: ContentType; label: string; description: string }[] = [
  { id: 'product_description', label: 'Description Produit', description: 'Fiche produit optimisee AEO' },
  { id: 'landing_page', label: 'Landing Page', description: 'Contenu de page d\'atterrissage' },
  { id: 'sales_email', label: 'Email Commercial', description: 'Email de prospection personnalise' },
  { id: 'meta_tags', label: 'Meta Tags', description: 'Title + description SEO/AEO' },
  { id: 'social_post', label: 'Post Social', description: 'Publication reseaux sociaux' },
  { id: 'press_release', label: 'Communique de Presse', description: 'CP structure et optimise' },
  { id: 'case_study', label: 'Etude de Cas', description: 'Temoignage client detaille' },
  { id: 'newsletter', label: 'Newsletter', description: 'Email marketing regulier' },
];

const TONES = [
  { id: 'professionnel', label: 'Professionnel' },
  { id: 'decontracte', label: 'Decontracte' },
  { id: 'autoritaire', label: 'Autoritaire' },
  { id: 'empathique', label: 'Empathique' },
  { id: 'technique', label: 'Technique' },
];

export default function ContentWriterPage() {
  const [step, setStep] = useState(0);
  const [vertical, setVertical] = useState<ContentVertical | null>(null);
  const [contentType, setContentType] = useState<ContentType | null>(null);
  const [brandName, setBrandName] = useState('');
  const [product, setProduct] = useState('');
  const [audience, setAudience] = useState('');
  const [tone, setTone] = useState('professionnel');
  const [generating, setGenerating] = useState(false);
  const [result, setResult] = useState<{ title: string; content: string; score: number; tips: string[] } | null>(null);
  const [copied, setCopied] = useState(false);

  const handleGenerate = () => {
    setGenerating(true);
    setTimeout(() => {
      setResult({
        title: `${contentType === 'landing_page' ? 'Landing Page' : contentType === 'product_description' ? 'Description Produit' : 'Contenu'} вҖ” ${brandName}`,
        content: `# ${brandName} вҖ” ${product}\n\n## Votre solution pour ${audience}\n\nDans un monde ou la visibilite digitale est essentielle, ${brandName} propose ${product} вҖ” une solution innovante conГ§ue specifiquement pour ${audience}.\n\n### Pourquoi choisir ${brandName} ?\n\n- **Expertise prouvee** : +500 clients satisfaits dans le secteur\n- **Technologie de pointe** : Algorithmes IA proprietaires\n- **Support premium** : Equipe dediee disponible 24/7\n- **ROI mesurable** : Resultats visibles des le premier mois\n\n### Comment Г§a fonctionne\n\n1. **Analyse initiale** вҖ” Audit complet de votre situation actuelle\n2. **Strategie sur mesure** вҖ” Plan d'action adapte a vos objectifs\n3. **Implementation** вҖ” Deploiement rapide et accompagne\n4. **Optimisation continue** вҖ” Amelioration iterative basee sur les donnees\n\n### Temoignage client\n\n> "${brandName} a transforme notre approche. En 3 mois, nous avons augmente notre visibilite IA de 150%." вҖ” Directeur Marketing, Client Premium\n\n### Commencez aujourd'hui\n\nRejoinissez les entreprises qui font confiance a ${brandName} pour leur strategie digitale.`,
        score: 84,
        tips: [
          'Ajouter des donnees chiffrees specifiques pour renforcer la credibilite',
          'Integrer un Schema.org Product ou Service pour le balisage structure',
          'Inclure une FAQ en bas de page pour maximiser l\'extractibilite IA',
          'Ajouter des liens internes vers des etudes de cas pour enrichir le contexte',
        ],
      });
      setGenerating(false);
      setStep(3);
    }, 2500);
  };

  const handleCopy = () => {
    if (result) {
      navigator.clipboard.writeText(result.content);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  return (
    <div className="p-4 sm:p-8 max-w-7xl mx-auto">
      <PageHeader
        title="Content Writer"
        description="Generez du contenu marketing optimise AEO pour votre verticale."
        breadcrumbs={[
          { label: 'App', href: '/app' },
          { label: 'Outils Generatifs', href: '/app/generative-tools' },
          { label: 'Content Writer' },
        ]}
      />

      {/* Progress Steps */}
      <div className="flex items-center justify-center gap-2 mb-10">
        {['Verticale', 'Type', 'Details', 'Resultat'].map((label, i) => (
          <div key={label} className="flex items-center gap-2">
            <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold transition-all ${
              step === i ? 'bg-primary text-black' : step > i ? 'bg-primary/20 text-primary' : 'bg-white/5 text-white/30'
            }`}>
              {step > i ? 'вң“' : i + 1}
            </div>
            <span className={`text-xs hidden sm:inline ${step === i ? 'text-white' : 'text-white/30'}`}>{label}</span>
            {i < 3 && <div className={`w-8 h-px ${step > i ? 'bg-primary/30' : 'bg-white/10'}`} />}
          </div>
        ))}
      </div>

      {/* Step 0: Vertical */}
      {step === 0 && (
        <div className="max-w-3xl mx-auto animate-fade-in-up">
          <h2 className="text-lg font-bold text-white mb-6 text-center">Choisissez votre verticale</h2>
          <div className="grid grid-cols-3 gap-3">
            {VERTICALS.map((v) => {
              const Icon = v.icon;
              return (
                <button
                  key={v.id}
                  onClick={() => { setVertical(v.id); setStep(1); }}
                  className={`p-4 rounded-xl border transition-all text-center hover:border-primary/30 hover:bg-primary/5 ${
                    vertical === v.id ? 'bg-primary/10 border-primary/30' : 'bg-white/[0.02] border-white/10'
                  }`}
                >
                  <Icon size={24} className="mx-auto mb-2 text-white/50" />
                  <span className="text-sm text-white font-medium">{v.label}</span>
                </button>
              );
            })}
          </div>
        </div>
      )}

      {/* Step 1: Content Type */}
      {step === 1 && (
        <div className="max-w-3xl mx-auto animate-fade-in-up">
          <h2 className="text-lg font-bold text-white mb-6 text-center">Type de contenu</h2>
          <div className="grid sm:grid-cols-2 gap-3">
            {CONTENT_TYPES.map((ct) => (
              <button
                key={ct.id}
                onClick={() => { setContentType(ct.id); setStep(2); }}
                className={`p-4 rounded-xl border transition-all text-left hover:border-primary/30 hover:bg-primary/5 ${
                  contentType === ct.id ? 'bg-primary/10 border-primary/30' : 'bg-white/[0.02] border-white/10'
                }`}
              >
                <span className="text-sm font-bold text-white">{ct.label}</span>
                <p className="text-xs text-white/40 mt-1">{ct.description}</p>
              </button>
            ))}
          </div>
          <div className="flex justify-start mt-6">
            <Button variant="outline" size="sm" onClick={() => setStep(0)} className="gap-1.5">
              <ArrowLeft size={14} /> Retour
            </Button>
          </div>
        </div>
      )}

      {/* Step 2: Details Form */}
      {step === 2 && (
        <div className="max-w-xl mx-auto animate-fade-in-up">
          <h2 className="text-lg font-bold text-white mb-6 text-center">Details du contenu</h2>
          <Card className="p-6 space-y-4">
            <div>
              <label className="block text-sm font-medium text-white/70 mb-1.5">Nom de la marque</label>
              <input
                type="text"
                value={brandName}
                onChange={(e) => setBrandName(e.target.value)}
                placeholder="Ex: CitedBy.ai"
                className="w-full bg-white/5 border border-white/10 rounded-xl p-3 text-white placeholder:text-white/30 focus:border-primary/50 focus:ring-2 focus:ring-primary/20 outline-none transition-all text-sm"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-white/70 mb-1.5">Produit / Service</label>
              <input
                type="text"
                value={product}
                onChange={(e) => setProduct(e.target.value)}
                placeholder="Ex: Plateforme d'optimisation AEO"
                className="w-full bg-white/5 border border-white/10 rounded-xl p-3 text-white placeholder:text-white/30 focus:border-primary/50 focus:ring-2 focus:ring-primary/20 outline-none transition-all text-sm"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-white/70 mb-1.5">Audience cible</label>
              <input
                type="text"
                value={audience}
                onChange={(e) => setAudience(e.target.value)}
                placeholder="Ex: Responsables marketing B2B"
                className="w-full bg-white/5 border border-white/10 rounded-xl p-3 text-white placeholder:text-white/30 focus:border-primary/50 focus:ring-2 focus:ring-primary/20 outline-none transition-all text-sm"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-white/70 mb-1.5">Ton</label>
              <div className="flex flex-wrap gap-2">
                {TONES.map((t) => (
                  <button
                    key={t.id}
                    onClick={() => setTone(t.id)}
                    className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${
                      tone === t.id ? 'bg-primary/20 text-primary border border-primary/30' : 'bg-white/5 text-white/50 border border-white/10 hover:border-white/20'
                    }`}
                  >
                    {t.label}
                  </button>
                ))}
              </div>
            </div>
            <div className="flex gap-3 pt-2">
              <Button variant="outline" onClick={() => setStep(1)} className="gap-1.5">
                <ArrowLeft size={14} /> Retour
              </Button>
              <Button
                onClick={handleGenerate}
                disabled={!brandName || !product || !audience || generating}
                className="flex-1 gap-2"
              >
                {generating ? (
                  <>
                    <Loader2 className="animate-spin" size={16} />
                    Generation...
                  </>
                ) : (
                  <>
                    <Sparkles size={16} />
                    Generer le contenu
                  </>
                )}
              </Button>
            </div>
          </Card>
        </div>
      )}

      {/* Step 3: Result */}
      {step === 3 && result && (
        <div className="max-w-4xl mx-auto animate-fade-in-up space-y-6">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <PenTool size={20} className="text-primary" />
              <h2 className="text-lg font-bold text-white">{result.title}</h2>
            </div>
            <div className="flex items-center gap-3">
              <Badge variant="success">Score AEO: {result.score}/100</Badge>
              <Button variant="outline" size="sm" onClick={handleCopy} className="gap-1.5">
                {copied ? <Check size={14} /> : <Copy size={14} />}
                {copied ? 'Copie !' : 'Copier'}
              </Button>
            </div>
          </div>

          <Card className="p-6">
            <div className="bg-white/[0.02] border border-white/5 rounded-xl p-6 max-h-[500px] overflow-y-auto">
              <pre className="whitespace-pre-wrap text-sm text-white/70 font-sans leading-relaxed">
                {result.content}
              </pre>
            </div>
          </Card>

          {/* AEO Tips */}
          <Card className="p-5">
            <h3 className="text-sm font-bold text-white mb-3 flex items-center gap-2">
              <Sparkles size={14} className="text-primary" />
              Conseils AEO
            </h3>
            <ul className="space-y-2">
              {result.tips.map((tip, i) => (
                <li key={i} className="flex items-start gap-2 text-xs text-white/50">
                  <ArrowRight size={12} className="text-primary shrink-0 mt-0.5" />
                  {tip}
                </li>
              ))}
            </ul>
          </Card>

          <div className="flex gap-3">
            <Button variant="outline" onClick={() => { setStep(0); setResult(null); }} className="gap-1.5">
              <ArrowLeft size={14} /> Nouveau contenu
            </Button>
          </div>
        </div>
      )}
    </div>
  );
}

