        </TabsContent>

        <TabsContent value="library">
          <div className="mt-6 space-y-4 animate-fade-in-up">
            {MOCK_SMC_CONTENTS.map((content) => {
              const typeColors: Record<string, string> = {
                fiche: 'bg-blue-500/10 text-blue-400',
                faq: 'bg-emerald-500/10 text-emerald-400',
                article: 'bg-purple-500/10 text-purple-400',
                brief: 'bg-amber-500/10 text-amber-400',
              };

              return (
                <Card key={content.id} className="p-5">
                  <div className="flex items-start justify-between gap-4 mb-3">
                    <div>
                      <div className="flex items-center gap-2 mb-1">
                        <Badge className={typeColors[content.type]}>{content.type}</Badge>
