                value={description}
                onChange={(e) => setDescription(e.target.value)}
                placeholder="Decrivez votre entreprise en 2-3 phrases..."
                rows={3}
                className="w-full bg-white/5 border border-white/10 rounded-xl p-2.5 text-white placeholder:text-white/30 focus:border-primary/50 outline-none transition-all text-sm resize-none"
              />
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="block text-xs font-medium text-white/50 mb-1">
                  <Calendar size={10} className="inline mr-1" />Type
                </label>
                <select
                  value={type}
                  onChange={(e) => setType(e.target.value)}
                  className="w-full bg-white/5 border border-white/10 rounded-xl p-2.5 text-white text-sm outline-none"
                >
                  <option value="SaaS">SaaS</option>
                  <option value="E-commerce">E-commerce</option>
                  <option value="Agency">Agence</option>
                  <option value="Consulting">Consulting</option>
                  <option value="Startup">Startup</option>
                  <option value="Enterprise">Entreprise</option>
                </select>
              </div>
              <div>
                <label className="block text-xs font-medium text-white/50 mb-1">
                  <Calendar size={10} className="inline mr-1" />Fondee en
                </label>
                <input
                  type="text"
                  value={founded}
                  onChange={(e) => setFounded(e.target.value)}
                  placeholder="2024"
                  className="w-full bg-white/5 border border-white/10 rounded-xl p-2.5 text-white placeholder:text-white/30 focus:border-primary/50 outline-none transition-all text-sm"
                />
              </div>
            </div>
            <div>
              <label className="block text-xs font-medium text-white/50 mb-1">
                <MapPin size={10} className="inline mr-1" />Localisation
              </label>
              <input
                type="text"
                value={location}
                onChange={(e) => setLocation(e.target.value)}
                placeholder="Paris, France"
                className="w-full bg-white/5 border border-white/10 rounded-xl p-2.5 text-white placeholder:text-white/30 focus:border-primary/50 outline-none transition-all text-sm"
              />
            </div>
          </Card>

          {/* Services */}
          <Card className="p-6 space-y-3">
            <div className="flex items-center justify-between">
              <h3 className="text-sm font-bold text-white">Services</h3>
              <button onClick={addService} className="text-xs text-primary hover:text-primary/80 flex items-center gap-1">
                <Plus size={12} /> Ajouter
              </button>
            </div>
            {services.map((s, i) => (
              <div key={i} className="space-y-2 p-3 bg-white/[0.02] rounded-xl">
                <div className="flex gap-2">
                  <input
                    type="text"
                    value={s.name}
                    onChange={(e) => updateService(i, 'name', e.target.value)}
                    placeholder="Nom du service"
                    className="flex-1 bg-white/5 border border-white/10 rounded-lg p-2 text-white placeholder:text-white/30 text-xs outline-none"
                  />
                  {services.length > 1 && (
                    <button onClick={() => removeService(i)} className="text-red-400/50 hover:text-red-400">
                      <Trash2 size={14} />
                    </button>
                  )}
                </div>
                <input
                  type="text"
                  value={s.description}
                  onChange={(e) => updateService(i, 'description', e.target.value)}
                  placeholder="Description courte"
                  className="w-full bg-white/5 border border-white/10 rounded-lg p-2 text-white placeholder:text-white/30 text-xs outline-none"
                />
              </div>
            ))}
          </Card>

          {/* FAQs */}
          <Card className="p-6 space-y-3">
            <div className="flex items-center justify-between">
              <h3 className="text-sm font-bold text-white">FAQ</h3>
              <button onClick={addFaq} className="text-xs text-primary hover:text-primary/80 flex items-center gap-1">
                <Plus size={12} /> Ajouter
              </button>
            </div>
            {faqs.map((f, i) => (
              <div key={i} className="space-y-2 p-3 bg-white/[0.02] rounded-xl">
                <div className="flex gap-2">
                  <input
                    type="text"
                    value={f.question}
                    onChange={(e) => updateFaq(i, 'question', e.target.value)}
                    placeholder="Question"
                    className="flex-1 bg-white/5 border border-white/10 rounded-lg p-2 text-white placeholder:text-white/30 text-xs outline-none"
                  />
                  {faqs.length > 1 && (
                    <button onClick={() => removeFaq(i)} className="text-red-400/50 hover:text-red-400">
                      <Trash2 size={14} />
                    </button>
                  )}
                </div>
                <textarea
                  value={f.answer}
                  onChange={(e) => updateFaq(i, 'answer', e.target.value)}
                  placeholder="Reponse"
                  rows={2}
                  className="w-full bg-white/5 border border-white/10 rounded-lg p-2 text-white placeholder:text-white/30 text-xs outline-none resize-none"
                />
              </div>
            ))}
          </Card>

          <Button
            onClick={handleGenerate}
            disabled={!companyName || !description || generating}
            className="w-full gap-2"
          >
            {generating ? (
              <>
                <Loader2 className="animate-spin" size={16} />
                Generation du llm.txt...
              </>
            ) : (
              <>
                <Sparkles size={16} />
                Generer le fichier llm.txt
              </>
            )}
          </Button>
        </div>

        {/* Output */}
        <div className="lg:col-span-7">
          {result ? (
            <div className="space-y-4 animate-fade-in-up">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Globe size={16} className="text-amber-400" />
                  <span className="text-sm font-bold text-white">llm.txt genere</span>
                </div>
                <div className="flex gap-2">
                  <Button variant="outline" size="sm" onClick={handleCopy} className="gap-1.5">
                    {copied ? <Check size={14} /> : <Copy size={14} />}
                    {copied ? 'Copie !' : 'Copier'}
                  </Button>
                  <Button variant="outline" size="sm" className="gap-1.5">
                    <Download size={14} /> Telecharger
                  </Button>
                </div>
              </div>
              <CodeBlock code={result} language="text" title="llm.txt" />
            </div>
          ) : (
            <div className="flex flex-col items-center justify-center h-full min-h-[500px] text-center">
              <div className="w-16 h-16 rounded-2xl bg-white/5 flex items-center justify-center mb-4">
                <Globe size={24} className="text-white/20" />
              </div>
              <p className="text-white/30 text-sm mb-2">
                Remplissez le formulaire et generez votre fichier llm.txt
              </p>
              <p className="text-white/20 text-xs max-w-xs">
                Ce fichier servira de source de verite pour les moteurs IA
              </p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

input.content:
'use client';

import { useState } from 'react';
import {
  Code,
  Sparkles,
  Loader2,
  Copy,
  Check,
  Building,
  Globe,
  ShoppingCart,
  User,
  HelpCircle,
  FileText,
} from 'lucide-react';
import { PageHeader } from '@/components/page-header';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { CodeBlock } from '@/components/code-block';

const SCHEMA_TYPES = [
  { id: 'Organization', label: 'Organization', description: 'Entreprise, association, marque', icon: Building },
  { id: 'WebSite', label: 'WebSite', description: 'Site web avec SearchAction', icon: Globe },
  { id: 'Product', label: 'Product', description: 'Produit avec prix et avis', icon: ShoppingCart },
  { id: 'Person', label: 'Person', description: 'Personne, auteur, expert', icon: User },
  { id: 'FAQPage', label: 'FAQPage', description: 'Page de questions/reponses', icon: HelpCircle },
  { id: 'Article', label: 'Article', description: 'Article de blog ou presse', icon: FileText },
];

export default function SchemaOrgPage() {
  const [selectedType, setSelectedType] = useState<string | null>(null);
  const [name, setName] = useState('');
  const [url, setUrl] = useState('');
  const [description, setDescription] = useState('');
  const [generating, setGenerating] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  const handleGenerate = () => {
    if (!selectedType || !name) return;
    setGenerating(true);

    setTimeout(() => {
      const schemas: Record<string, object> = {
        Organization: {
          '@context': 'https://schema.org',
          '@type': 'Organization',
          name,
          url: url || `https://${name.toLowerCase().replace(/\s+/g, '')}.com`,
          description: description || `${name} - Solution innovante`,
          logo: `${url || 'https://example.com'}/logo.png`,
          sameAs: [
            'https://twitter.com/example',
            'https://linkedin.com/company/example',
          ],
          contactPoint: {
            '@type': 'ContactPoint',
            telephone: '+33-1-00-00-00-00',
            contactType: 'customer service',
            availableLanguage: ['French', 'English'],
          },
        },
        WebSite: {
          '@context': 'https://schema.org',
          '@type': 'WebSite',
          name,
          url: url || `https://${name.toLowerCase().replace(/\s+/g, '')}.com`,
          description: description || `${name} - Site officiel`,
          potentialAction: {
            '@type': 'SearchAction',
            target: {
              '@type': 'EntryPoint',
              urlTemplate: `${url || 'https://example.com'}/search?q={search_term_string}`,
            },
            'query-input': 'required name=search_term_string',
          },
        },
        Product: {
          '@context': 'https://schema.org',
          '@type': 'Product',
          name,
          description: description || `${name} - Produit premium`,
          url: url || 'https://example.com/product',
          brand: { '@type': 'Brand', name },
          offers: {
            '@type': 'Offer',
            price: '49.00',
            priceCurrency: 'EUR',
            availability: 'https://schema.org/InStock',
          },
          aggregateRating: {
            '@type': 'AggregateRating',
            ratingValue: '4.8',
            reviewCount: '127',
          },
        },
        Person: {
          '@context': 'https://schema.org',
          '@type': 'Person',
          name,
          url: url || 'https://example.com',
          description: description || `${name} - Expert`,
          jobTitle: 'CEO & Founder',
          worksFor: { '@type': 'Organization', name: 'Company' },
          sameAs: ['https://twitter.com/example', 'https://linkedin.com/in/example'],
        },
        FAQPage: {
          '@context': 'https://schema.org',
          '@type': 'FAQPage',
          mainEntity: [
            {
              '@type': 'Question',
              name: `Qu'est-ce que ${name} ?`,
              acceptedAnswer: {
                '@type': 'Answer',
                text: description || `${name} est une solution innovante.`,
              },
            },
            {
              '@type': 'Question',
              name: `Comment fonctionne ${name} ?`,
              acceptedAnswer: {
                '@type': 'Answer',
                text: `${name} utilise une technologie avancee pour fournir des resultats optimaux.`,
              },
            },
            {
              '@type': 'Question',
              name: `Quels sont les tarifs de ${name} ?`,
              acceptedAnswer: {
                '@type': 'Answer',
                text: `${name} propose plusieurs formules adaptees a chaque besoin.`,
              },
            },
          ],
        },
        Article: {
          '@context': 'https://schema.org',
          '@type': 'Article',
          headline: name,
          description: description || `Article sur ${name}`,
          url: url || 'https://example.com/article',
          author: { '@type': 'Organization', name: 'CitedBy.ai' },
          publisher: {
            '@type': 'Organization',
            name: 'CitedBy.ai',
            logo: { '@type': 'ImageObject', url: 'https://citedby.ai/logo.png' },
          },
          datePublished: new Date().toISOString().split('T')[0],
          dateModified: new Date().toISOString().split('T')[0],
        },
      };

      setResult(JSON.stringify(schemas[selectedType] || schemas.Organization, null, 2));
      setGenerating(false);
    }, 1500);
  };

  const handleCopy = () => {
    if (result) {
      navigator.clipboard.writeText(result);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  return (
    <div className="p-4 sm:p-8 max-w-7xl mx-auto">
      <PageHeader
        title="Schema.org Generator"
        description="Generez le balisage JSON-LD structure pour connecter votre marque au Knowledge Graph."
        breadcrumbs={[
          { label: 'App', href: '/app' },
          { label: 'Outils Generatifs', href: '/app/generative-tools' },
          { label: 'Schema.org' },
        ]}
      />

      <div className="grid lg:grid-cols-12 gap-8 animate-fade-in-up">
        {/* Form */}
        <div className="lg:col-span-5 space-y-6">
          {/* Type Selection */}
          <div>
            <h3 className="text-sm font-medium text-white/50 uppercase tracking-wider mb-3">
              Type de Schema
            </h3>
            <div className="grid grid-cols-2 gap-2">
              {SCHEMA_TYPES.map((st) => {
                const Icon = st.icon;
                const isSelected = selectedType === st.id;
                return (
                  <button
                    key={st.id}
                    onClick={() => setSelectedType(st.id)}
                    className={`p-3 rounded-xl border transition-all text-left ${
                      isSelected
                        ? 'bg-primary/10 border-primary/30'
                        : 'bg-white/[0.02] border-white/10 hover:border-white/20'
                    }`}
                  >
                    <Icon size={16} className={isSelected ? 'text-primary mb-1' : 'text-white/40 mb-1'} />
                    <p className="text-xs font-bold text-white">{st.label}</p>
                    <p className="text-[10px] text-white/30">{st.description}</p>
                  </button>
                );
              })}
            </div>
          </div>

          {/* Details */}
          {selectedType && (
            <Card className="p-5 space-y-4 animate-fade-in-up">
              <div>
                <label className="block text-xs font-medium text-white/50 mb-1">Nom *</label>
                <input
                  type="text"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  placeholder="Ex: CitedBy.ai"
                  className="w-full bg-white/5 border border-white/10 rounded-xl p-2.5 text-white placeholder:text-white/30 focus:border-primary/50 outline-none transition-all text-sm"
                />
              </div>
              <div>
                <label className="block text-xs font-medium text-white/50 mb-1">URL</label>
                <input
                  type="url"
                  value={url}
                  onChange={(e) => setUrl(e.target.value)}
                  placeholder="https://..."
                  className="w-full bg-white/5 border border-white/10 rounded-xl p-2.5 text-white placeholder:text-white/30 focus:border-primary/50 outline-none transition-all text-sm"
                />
              </div>
              <div>
                <label className="block text-xs font-medium text-white/50 mb-1">Description</label>
                <textarea
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  placeholder="Description courte..."
                  rows={2}
                  className="w-full bg-white/5 border border-white/10 rounded-xl p-2.5 text-white placeholder:text-white/30 focus:border-primary/50 outline-none transition-all text-sm resize-none"
                />
              </div>
              <Button
                onClick={handleGenerate}
                disabled={!name || generating}
                className="w-full gap-2"
              >
                {generating ? (
                  <>
                    <Loader2 className="animate-spin" size={16} />
                    Generation...
                  </>
                ) : (
                  <>
                    <Sparkles size={16} />
                    Generer le JSON-LD
                  </>
                )}
              </Button>
            </Card>
          )}
        </div>

        {/* Output */}
        <div className="lg:col-span-7">
          {result ? (
            <div className="space-y-4 animate-fade-in-up">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Code size={16} className="text-orange-400" />
                  <span className="text-sm font-bold text-white">JSON-LD genere</span>
                  <Badge variant="success" className="text-[10px]">{selectedType}</Badge>
                </div>
                <Button variant="outline" size="sm" onClick={handleCopy} className="gap-1.5">
                  {copied ? <Check size={14} /> : <Copy size={14} />}
                  {copied ? 'Copie !' : 'Copier'}
                </Button>
              </div>
              <CodeBlock
                code={`<script type="application/ld+json">\n${result}\n</script>`}
                language="json"
                title="Schema.org JSON-LD"
              />
              <Card className="p-4">
                <p className="text-xs text-white/40">
                  <span className="text-primary font-medium">Tip:</span> Collez ce code dans le{' '}
                  <code className="text-white/60 bg-white/5 px-1 rounded">&lt;head&gt;</code> de votre page HTML
                  pour que les moteurs de recherche et IA comprennent votre contenu.
                </p>
              </Card>
            </div>
          ) : (
            <div className="flex flex-col items-center justify-center h-full min-h-[400px] text-center">
              <div className="w-16 h-16 rounded-2xl bg-white/5 flex items-center justify-center mb-4">
                <Code size={24} className="text-white/20" />
              </div>
              <p className="text-white/30 text-sm mb-2">
                Selectionnez un type et remplissez les details
              </p>
              <p className="text-white/20 text-xs">
                Le JSON-LD sera genere automatiquement
              </p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

