'use client';

import { useState } from 'react';
import {
  Bot,
  Copy,
  Check,
  Download,
  Sparkles,
  Shield,
  AlertTriangle,
} from 'lucide-react';
import { PageHeader } from '@/components/page-header';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { CodeBlock } from '@/components/code-block';

const AI_BOTS = [
  { id: 'GPTBot', name: 'GPTBot', company: 'OpenAI (ChatGPT)', color: 'text-green-400' },
  { id: 'ClaudeBot', name: 'ClaudeBot', company: 'Anthropic (Claude)', color: 'text-purple-400' },
  { id: 'Google-Extended', name: 'Google-Extended', company: 'Google (Gemini)', color: 'text-blue-400' },
  { id: 'PerplexityBot', name: 'PerplexityBot', company: 'Perplexity', color: 'text-cyan-400' },
  { id: 'Bytespider', name: 'Bytespider', company: 'ByteDance (TikTok)', color: 'text-pink-400' },
  { id: 'CCBot', name: 'CCBot', company: 'Common Crawl', color: 'text-amber-400' },
];

const PLATFORMS = [
  { id: 'wordpress', label: 'WordPress' },
  { id: 'nextjs', label: 'Next.js' },
  { id: 'shopify', label: 'Shopify' },
  { id: 'custom', label: 'Custom' },
];

export default function RobotsTxtPage() {
  const [platform, setPlatform] = useState('custom');
  const [allowedBots, setAllowedBots] = useState<Record<string, boolean>>({
    GPTBot: true,
    ClaudeBot: true,
    'Google-Extended': true,
    PerplexityBot: true,
    Bytespider: false,
    CCBot: false,
  });
  const [sitemapUrl, setSitemapUrl] = useState('');
  const [copied, setCopied] = useState(false);

  const toggleBot = (id: string) => {
    setAllowedBots((prev) => ({ ...prev, [id]: !prev[id] }));
  };

  const allowAll = () => {
    const updated: Record<string, boolean> = {};
    AI_BOTS.forEach((b) => { updated[b.id] = true; });
    setAllowedBots(updated);
  };

  const blockAll = () => {
    const updated: Record<string, boolean> = {};
    AI_BOTS.forEach((b) => { updated[b.id] = false; });
    setAllowedBots(updated);
  };

  const allowedCount = Object.values(allowedBots).filter(Boolean).length;
  const blockedCount = AI_BOTS.length - allowedCount;

  const generateRobotsTxt = () => {
    let content = `# robots.txt вҖ” Generated by CitedBy.ai\n# Platform: ${platform}\n# Date: ${new Date().toISOString().split('T')[0]}\n\n`;

    // General rules
    content += `# General crawlers\nUser-agent: *\nAllow: /\n`;

    if (platform === 'wordpress') {
      content += `Disallow: /wp-admin/\nDisallow: /wp-includes/\nAllow: /wp-admin/admin-ajax.php\n`;
    } else if (platform === 'nextjs') {
      content += `Disallow: /_next/static/\nDisallow: /api/\n`;
    } else if (platform === 'shopify') {
      content += `Disallow: /admin/\nDisallow: /cart/\nDisallow: /checkout/\n`;
    }

    content += '\n';

    // AI Bots - Allowed
    const allowed = AI_BOTS.filter((b) => allowedBots[b.id]);
    const blocked = AI_BOTS.filter((b) => !allowedBots[b.id]);

    if (allowed.length > 0) {
      content += `# AI Bots вҖ” Allowed\n`;
      allowed.forEach((b) => {
        content += `User-agent: ${b.id}\nAllow: /\n\n`;
      });
    }

    if (blocked.length > 0) {
      content += `# AI Bots вҖ” Blocked\n`;
      blocked.forEach((b) => {
        content += `User-agent: ${b.id}\nDisallow: /\n\n`;
      });
    }

    // Sitemap
    if (sitemapUrl) {
      content += `# Sitemap\nSitemap: ${sitemapUrl}\n`;
    } else {
      content += `# Sitemap\n# Sitemap: https://yoursite.com/sitemap.xml\n`;
    }

    return content;
  };

  const robotsTxt = generateRobotsTxt();

  const handleCopy = () => {
    navigator.clipboard.writeText(robotsTxt);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="p-4 sm:p-8 max-w-7xl mx-auto">
      <PageHeader
        title="Robots.txt Optimizer"
        description="Optimisez votre robots.txt pour autoriser les bots IA tout en securisant votre site."
        breadcrumbs={[
          { label: 'App', href: '/app' },
          { label: 'Outils Generatifs', href: '/app/generative-tools' },
          { label: 'Robots.txt' },
        ]}
      />

      <div className="grid lg:grid-cols-12 gap-8 animate-fade-in-up">
        {/* Configuration */}
        <div className="lg:col-span-5 space-y-6">
          {/* Platform */}
          <Card className="p-5">
            <h3 className="text-sm font-bold text-white mb-3">Plateforme</h3>
            <div className="grid grid-cols-2 gap-2">
              {PLATFORMS.map((p) => (
                <button
                  key={p.id}
                  onClick={() => setPlatform(p.id)}
                  className={`p-2.5 rounded-xl border text-sm font-medium transition-all ${
                    platform === p.id
                      ? 'bg-primary/10 border-primary/30 text-primary'
                      : 'bg-white/[0.02] border-white/10 text-white/50 hover:border-white/20'
                  }`}
                >
                utorises</span>
              </div>
              <div className="flex items-center gap-1.5">
                <AlertTriangle size={12} className="text-red-400" />
                <span className="text-xs text-white/50">{blockedCount} bloques</span>
              </div>
            </div>
          </Card>

          {/* Sitemap */}
          <Card className="p-5">
            <h3 className="text-sm font-bold text-white mb-3">Sitemap (optionnel)</h3>
            <input
              type="url"
              value={sitemapUrl}
              onChange={(e) => setSitemapUrl(e.target.value)}
              placeholder="https://yoursite.com/sitemap.xml"
              className="w-full bg-white/5 border border-white/10 rounded-xl p-2.5 text-white placeholder:text-white/30 focus:border-primary/50 outline-none transition-all text-sm"
            />
          </Card>
        </div>

        {/* Output */}
        <div className="lg:col-span-7 space-y-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Sparkles size={16} className="text-cyan-400" />
              <span className="text-sm font-bold text-white">robots.txt</span>
              <Badge variant="secondary" className="text-[10px]">{platform}</Badge>
            </div>
            <div className="flex gap-2">
              <Button variant="outline" size="sm" onClick={handleCopy} className="gap-1.5">
                {copied ? <Check size={14} /> : <Copy size={14} />}
                {copied ? 'Copie !' : 'Copier'}
              </Button>
              <Button variant="outline" size="sm" className="gap-1.5">
                <Download size={14} /> Telecharger
              </Button>
            </div>
          </div>

          <CodeBlock code={robotsTxt} language="text" title="robots.txt" />

          <Card className="p-4">
            <p className="text-xs text-white/40">
              <span className="text-primary font-medium">Important:</span> Placez ce fichier a la racine de votre site
              web (ex: <code className="text-white/60 bg-white/5 px-1 rounded">https://votresite.com/robots.txt</code>).
              Les modifications prennent effet immediatement.
            </p>
          </Card>
        </div>
      </div>
    </div>
  );
}

