"use client";

import React, { useState } from "react";
import {
  User,
  Mail,
  Lock,
  Bell,
  BellOff,
  Download,
  Trash2,
  Save,
  Shield,
  AlertTriangle,
  Eye,
  EyeOff,
} from "lucide-react";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { PageHeader } from "@/components/page-header";
import { MOCK_USER } from "@/lib/mock-data";
import { toast } from "sonner";

export default function AccountPage() {
  // Profile state
  const [name, setName] = useState(MOCK_USER.name);
  const [email, setEmail] = useState(MOCK_USER.email);
  const [profileLoading, setProfileLoading] = useState(false);

  // Password state
  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [passwordLoading, setPasswordLoading] = useState(false);
  const [showCurrentPassword, setShowCurrentPassword] = useState(false);
  const [showNewPassword, setShowNewPassword] = useState(false);

  // Notification preferences
  const [emailAlerts, setEmailAlerts] = useState(true);
  const [weeklyDigest, setWeeklyDigest] = useState(true);
  const [marketing, setMarketing] = useState(false);

  // Actions loading
  const [exportLoading, setExportLoading] = useState(false);
  const [deleteConfirm, setDeleteConfirm] = useState(false);
  const [deleteLoading, setDeleteLoading] = useState(false);

  const handleProfileSave = () => {
    setProfileLoading(true);
    setTimeout(() => {
      setProfileLoading(false);
      toast.success("Profil mis a jour", {
        description: "Vos informations ont ete enregistrees avec succes.",
      });
    }, 1500);
  };

  const handlePasswordChange = () => {
    if (!currentPassword) {
      toast.error("Veuillez saisir votre mot de passe actuel");
      return;
    }
    if (newPassword.length < 8) {
      toast.error("Le nouveau mot de passe doit contenir au moins 8 caracteres");
      return;
    }
    if (newPassword !== confirmPassword) {
      toast.error("Les mots de passe ne correspondent pas");
      return;
    }

    setPasswordLoading(true);
    setTimeout(() => {
      setPasswordLoading(false);
      setCurrentPassword("");
      setNewPassword("");
      setConfirmPassword("");
      toast.success("Mot de passe modifie", {
        description: "Votre mot de passe a ete mis a jour avec succes.",
      });
    }, 1500);
  };

  const handleNotificationToggle = (
    key: "emailAlerts" | "weeklyDigest" | "marketing",
    value: boolean
  ) => {
    switch (key) {
      case "emailAlerts":
        setEmailAlerts(value);
        break;
      case "weeklyDigest":
        setWeeklyDigest(value);
        break;
      case "marketing":
        setMarketing(value);
        break;
    }
    toast.success("Preferences mises a jour");
  };

  const handleExportData = () => {
    setExportLoading(true);
    toast.loading("Preparation de l'export...", { id: "export" });
    setTimeout(() => {
      setExportLoading(false);
      toast.success("Export pret", {
        id: "export",
        description:
          "Un lien de telechargement a ete envoye a votre adresse email.",
      });
    }, 3000);
  };

  const handleDeleteAccount = () => {
    if (!deleteConfirm) {
      setDeleteConfirm(true);
      return;
    }

    setDeleteLoading(true);
    toast.loading("Suppression en cours...", { id: "delete" });
    setTimeout(() => {
      setDeleteLoading(false);
      setDeleteConfirm(false);
      toast.error("Suppression annulee", {
        id: "delete",
        description:
          "Cette action est desactivee en mode demonstration.",
      });
    }, 2000);
  };

  return (
    <div className="p-4 sm:p-8 max-w-7xl mx-auto">
      <PageHeader
        title="Mon compte"
        description="Gerez votre profil et vos preferences"
      />

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Main content */}
        <div className="lg:col-span-2 space-y-6">
          {/* Profile Section */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <User className="h-5 w-5 text-primary" />
                Informations personnelles
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                <Input
                  label="Nom complet"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  icon={<User className="h-4 w-4" />}
                  placeholder="Votre nom"
                />
                <Input
                  label="Adresse email"
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  icon={<Mail className="h-4 w-4" />}
                  placeholder="votre@email.com"
                />
                <div className="flex items-center gap-3 pt-2">
                  <Badge variant="outline" className="capitalize">
                    Plan {MOCK_USER.plan}
                  </Badge>
                  <Badge variant="secondary">
                    {MOCK_USER.credits} credits
                  </Badge>
                </div>
                <div className="flex justify-end pt-2">
                  <Button
                    onClick={handleProfileSave}
                    isLoading={profileLoading}
                  >
                    <Save className="h-4 w-4" />
                    Enregistrer
                  </Button>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Password Section */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Lock className="h-5 w-5 text-primary" />
                Changer le mot de passe
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                <div className="relative">
                  <Input
                    label="Mot de passe actuel"
                    type={showCurrentPassword ? "text" : "password"}
                    value={currentPassword}
                    onChange={(e) => setCurrentPassword(e.target.value)}
                    icon={<Lock className="h-4 w-4" />}
                    placeholder="Votre mot de passe actuel"
                  />
                  <button
                    type="button"
                    onClick={() => setShowCurrentPassword(!showCurrentPassword)}
                    className="absolute right-3 top-[38px] text-white/30 hover:text-white/60 transition-colors"
                  >
                    {showCurrentPassword ? (
                      <EyeOff className="h-4 w-4" />
                    ) : (
                      <Eye className="h-4 w-4" />
                    )}
                  </button>
                </div>

                <div className="relative">
                  <Input
                    label="Nouveau mot de passe"
                    type={showNewPassword ? "text" : "password"}
                    value={newPassword}
                    onChange={(e) => setNewPassword(e.target.value)}
                    icon={<Shield className="h-4 w-4" />}
                    placeholder="Minimum 8 caracteres"
                  />
                  <button
                    type="button"
                    onClick={() => setShowNewPassword(!showNewPassword)}
                    className="absolute right-3 top-[38px] text-white/30 hover:text-white/60 transition-colors"
                  >
                    {showNewPassword ? (
                      <EyeOff className="h-4 w-4" />
                    ) : (
                      <Eye className="h-4 w-4" />
                    )}
                  </button>
                </div>

                <Input
                  label="Confirmer le mot de passe"
                  type="password"
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  icon={<Shield className="h-4 w-4" />}
                  placeholder="Retapez le nouveau mot de passe"
                  error={
                    confirmPassword && newPassword !== confirmPassword
                      ? "Les mots de passe ne correspondent pas"
                      : undefined
                  }
                />

                {newPassword && (
                  <div className="p-3 rounded-xl bg-white/5 border border-white/5">
                    <p className="text-xs text-white/40 mb-2">
                      Force du mot de passe :
                    </p>
                    <div className="flex gap-1">
                      {[1, 2, 3, 4].map((level) => (
                        <div
                          key={level}
                          className={`h-1.5 flex-1 rounded-full ${
                            newPassword.length >= level * 3
                              ? level <= 1
                                ? "bg-red-500"
                                : level <= 2
                                ? "bg-orange-500"
                                : level <= 3
                                ? "bg-amber-500"
                                : "bg-emerald-500"
                              : "bg-white/10"
                          }`}
                        />
                      ))}
                    </div>
                  </div>
                )}

                <div className="flex justify-end pt-2">
                  <Button
                    onClick={handlePasswordChange}
                    isLoading={passwordLoading}
                    disabled={!currentPassword || !newPassword || !confirmPassword}
                  >
                    <Lock className="h-4 w-4" />
                    Modifier le mot de passe
                  </Button>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Danger Zone */}
          <Card className="border-red-500/20">
            <CardHeader>
              <CardTitle className="flex items-center gap-2 text-red-400">
                <AlertTriangle className="h-5 w-5" />
                Zone de danger
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                <div className="p-4 rounded-xl bg-red-500/5 border border-red-500/10">
                  <h4 className="text-sm font-medium text-red-400 mb-1">
                    Supprimer mon compte
                  </h4>
                  <p className="text-xs text-white/40 mb-4">
                    Cette action est irreversible. Toutes vos donnees, projets
                    et credits seront definitivement supprimes.
                  </p>
                  <Button
                    variant="destructive"
                    size="sm"
                    onClick={handleDeleteAccount}
                    isLoading={deleteLoading}
                  >
                    <Trash2 className="h-4 w-4" />
                    {deleteConfirm
                      ? "Confirmer la suppression"
                      : "Supprimer mon compte"}
                  </Button>
                  {deleteConfirm && !deleteLoading && (
                    <Button
                      variant="ghost"
                      size="sm"
                      className="ml-2"
                      onClick={() => setDeleteConfirm(false)}
                    >
                      Annuler
                    </Button>
                  )}
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Sidebar */}
        <div className="space-y-6">
          {/* Notification Preferences */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Bell className="h-5 w-5 text-primary" />
                Notifications
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                {/* Email Alerts Toggle */}
                <div className="flex items-center justify-between">
                  <div className="flex-1 pr-4">
                    <p className="text-sm font-medium text-white">
                      Alertes email
                    </p>
                    <p className="text-xs text-white/40">
                      Nouvelles citations et mentions
                    </p>
                  </div>
                  <button
                    onClick={() =>
                      handleNotificationToggle("emailAlerts", !emailAlerts)
                    }
                    className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                      emailAlerts ? "bg-primary" : "bg-white/10"
                    }`}
                  >
                    <span
                      className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                        emailAlerts ? "translate-x-6" : "translate-x-1"
                      }`}
                    />
                  </button>
                </div>

                {/* Weekly Digest Toggle */}
                <div className="flex items-center justify-between">
                  <div className="flex-1 pr-4">
                    <p className="text-sm font-medium text-white">
                      Digest hebdomadaire
                    </p>
                    <p className="text-xs text-white/40">
                      Resume de vos performances
                    </p>
                  </div>
                  <button
                    onClick={() =>
                      handleNotificationToggle("weeklyDigest", !weeklyDigest)
                    }
                    className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                      weeklyDigest ? "bg-primary" : "bg-white/10"
                    }`}
                  >
                    <span
                      className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                        weeklyDigest ? "translate-x-6" : "translate-x-1"
                      }`}
                    />
                  </button>
                </div>

                {/* Marketing Toggle */}
                <div className="flex items-center justify-between">
                  <div className="flex-1 pr-4">
                    <p className="text-sm font-medium text-white">
                      Communications marketing
                    </p>
                    <p className="text-xs text-white/40">
                      Nouveautes et offres speciales
                    </p>
                  </div>
                  <button
                    onClick={() =>
                      handleNotificationToggle("marketing", !marketing)
                    }
                    className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                      marketing ? "bg-primary" : "bg-white/10"
                    }`}
                  >
                    <span
                      className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                        marketing ? "translate-x-6" : "translate-x-1"
                      }`}
                    />
                  </button>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Data Export */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Download className="h-5 w-5 text-primary" />
                Export des donnees
              </CardTitle>
            </CardHeader>
            <CardContent>
              <p className="text-sm text-white/40 mb-4">
                Telechargez une copie de toutes vos donnees au format JSON.
                L&apos;export inclut vos projets, analyses, et contenus generes.
              </p>
              <Button
                variant="outline"
                className="w-full"
                onClick={handleExportData}
                isLoading={exportLoading}
              >
                <Download className="h-4 w-4" />
                Exporter mes donnees
              </Button>
            </CardContent>
          </Card>

          {/* Account Info */}
          <Card className="p-5">
            <h3 className="text-sm font-medium text-white/40 mb-3">
              Informations du compte
            </h3>
            <div className="space-y-2.5">
              <div className="flex items-center justify-between text-sm">
                <span className="text-white/40">ID utilisateur</span>
                <span className="text-white/60 font-mono text-xs">
                  {MOCK_USER.id}
                </span>
              </div>
              <div className="flex items-center justify-between text-sm">
                <span className="text-white/40">Plan</span>
                <Badge variant="default" className="capitalize">
                  {MOCK_USER.plan}
                </Badge>
              </div>
