const { chromium } = require('playwright-core');

(async () => {
  const browser = await chromium.launch({
    executablePath: String.raw`C:\Users\User\AppData\Local\ms-playwright\chromium-1208\chrome-win64\chrome.exe`,
    headless: false,
  });
  const context = await browser.newContext({
    viewport: { width: 1440, height: 900 },
  });
  const page = await context.newPage();

  // Log ALL failed requests
  page.on('requestfailed', request => {
    console.log('FAILED:', request.url(), request.failure().errorText);
  });

  // Log response errors
  page.on('response', response => {
    if (response.status() >= 400) {
      console.log('HTTP ERROR:', response.status(), response.url());
    }
  });

  await page.goto('http://localhost:3000', { waitUntil: 'networkidle', timeout: 30000 });
  await page.waitForTimeout(3000);

  // Check stylesheets
  const styleCount = await page.evaluate(() => document.styleSheets.length);
  console.log('Stylesheets loaded:', styleCount);

  // Check if body has classes
  const bodyClass = await page.evaluate(() => document.body.className);
  console.log('Body classes:', bodyClass);

  // Check html classes
  const htmlClass = await page.evaluate(() => document.documentElement.className);
  console.log('HTML classes:', htmlClass);

  await page.screenshot({ path: String.raw`C:\Users\User\Downloads\screenshot-landing5.png`, fullPage: false });
  console.log('Screenshot saved');
  await browser.close();
})();

